// Cast time system (RO pre-renewal)
// activeCasts: characterId → { skillId, targetId, isEnemy, learnedLevel, levelData, skill, castStartTime, castEndTime, actualCastTime, socketId }
const activeCasts = new Map();
// afterCastDelayEnd: characterId → timestamp when ACD expires (global skill lockout)
const afterCastDelayEnd = new Map();

// Calculate actual cast time after DEX reduction (RO pre-renewal formula)
// ActualCastTime = BaseCastTime × (1 - DEX/150) × (100 + equipCastRate) / 100
// DEX >= 150 → instant cast
// equipCastRate: negative = faster (e.g., -10 = 10% faster), from bCastrate
function calculateActualCastTime(baseCastTime, casterDex, equipCastRate) {
    if (baseCastTime <= 0) return 0;
    if (casterDex >= 150) return 0;
    let castTime = Math.floor(baseCastTime * (1 - casterDex / 150));
    // Apply equipment cast rate modifier (bCastrate: negative = faster)
    if (equipCastRate) {
        castTime = Math.floor(castTime * (100 + equipCastRate) / 100);
    }
    return Math.max(0, castTime);
}

// Interrupt a player's active cast (called when they take damage or move)
// Phase 3: bNoCastCancel (Phen Card) prevents damage interruption
function interruptCast(characterId, reason) {
    const cast = activeCasts.get(characterId);
    if (!cast) return;

    // Uninterruptible skills (e.g. Redemptio) cannot be interrupted by any reason
    if (cast.skill && cast.skill.uninterruptible) return;

    // Phase 3: noCastCancel prevents interruption from damage (but not from movement)
    if (reason === 'damage') {
        const castPlayer = connectedPlayers.get(characterId);
        if (castPlayer && castPlayer.cardNoCastCancel) return; // Phen Card: immune to damage interrupt
    }

    activeCasts.delete(characterId);
    const sock = io.sockets.sockets.get(cast.socketId);
    if (sock) sock.emit('skill:cast_interrupted', { skillId: cast.skillId, reason });
    const castPlayer = connectedPlayers.get(characterId);
    const castZone = (castPlayer && castPlayer.zone) || 'prontera_south';
    broadcastToZone(castZone, 'skill:cast_interrupted_broadcast', { casterId: characterId, skillId: cast.skillId });
    logger.info(`[CAST] ${cast.casterName}'s ${cast.skill.displayName} interrupted (${reason})`);
}

// ============================================================
// ============================================================
// Ground Effects System (Fire Wall, Safety Wall)
// ============================================================
const activeGroundEffects = new Map(); // effectId → { type, casterId, x, y, z, ... }
let groundEffectIdCounter = 0;

function createGroundEffect(def) {
    // Land Protector blocking: prevent ground effects from being placed in LP area
    const LP_BLOCKED_TYPES = new Set([
        'safety_wall', 'pneuma', 'warp_portal', 'sanctuary', 'magnus_exorcismus',
        'volcano', 'deluge', 'violent_gale', 'fire_wall', 'fire_pillar',
        'storm_gust', 'lord_of_vermilion', 'meteor_storm', 'quagmire', 'ice_wall'
    ]);
    if (LP_BLOCKED_TYPES.has(def.type)) {
        const now = Date.now();
        for (const [, eff] of activeGroundEffects.entries()) {
            if (eff.type !== 'land_protector' || now >= eff.expiresAt) continue;
            if (eff.zone !== def.zone) continue;
            const dx = (def.x || 0) - eff.x, dy = (def.y || 0) - eff.y;
            if (Math.sqrt(dx * dx + dy * dy) <= eff.radius) {
                return null; // Blocked by Land Protector
            }
        }
    }

    const id = ++groundEffectIdCounter;
    activeGroundEffects.set(id, { ...def, id, createdAt: Date.now(), expiresAt: Date.now() + def.duration });
    return id;
}

function removeGroundEffect(id) {
    activeGroundEffects.delete(id);
}

function getGroundEffectsAtPosition(x, y, z, radius) {
    const effects = [];
    for (const [id, effect] of activeGroundEffects.entries()) {
        if (Date.now() >= effect.expiresAt) continue;
        const dx = x - effect.x;
        const dy = y - effect.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist <= radius) effects.push(effect);
    }
    return effects;
}

// Count active ground effects by type and caster
function countGroundEffects(casterId, type) {
    let count = 0;
    for (const [, effect] of activeGroundEffects.entries()) {
        if (effect.casterId === casterId && effect.type === type && Date.now() < effect.expiresAt) count++;
    }
    return count;
}

// Remove oldest ground effect of a type by caster
function removeOldestGroundEffect(casterId, type) {
    let oldest = null;
    let oldestId = null;
    for (const [id, effect] of activeGroundEffects.entries()) {
        if (effect.casterId === casterId && effect.type === type) {
            if (!oldest || effect.createdAt < oldest.createdAt) {
                oldest = effect;
                oldestId = id;
            }
        }
    }
    if (oldestId) activeGroundEffects.delete(oldestId);
    return oldestId;
}

// ============================================================
// Skill Combat System — Passives, Buffs, Cooldowns, HP Regen
// ============================================================

// Get passive skill bonuses for a player (Sword Mastery, 2H Sword Mastery, HP Recovery)
function getPassiveSkillBonuses(player) {
    const bonuses = {
        bonusATK: 0, hpRegenBonus: 0, spRegenBonus: 0, bonusMDEF: 0,
        bonusDEX: 0, bonusHIT: 0, bonusRange: 0, bonusFLEE: 0,
        doubleAttackChance: 0,
        raceATK: {},
        raceDEF: {},
        fatalBlowChance: 0,
        movingHPRecovery: false,
        // Dual Wield Mastery (Assassin)
        rightHandMasteryLv: 0,
        leftHandMasteryLv: 0,
        katarMasteryATK: 0,
        // Mount System (Knight/Crusader)
        cavalierMasteryLv: 0,
        spearMasteryLv: 0,
    };
    const learned = player.learnedSkills || {};
    const wType = player.weaponType || null;

    // Sword Mastery (100/1705): +4 ATK/level with daggers & 1H swords (Swordsman & Rogue — non-stacking, use higher)
    const smLv = Math.max(learned[100] || 0, learned[1705] || 0);
    if (smLv > 0 && (wType === 'dagger' || wType === 'one_hand_sword')) {
        bonuses.bonusATK += smLv * 4;
    }
    // Two-Handed Sword Mastery (101): +4 ATK/level with 2H swords
    const tsmLv = learned[101] || 0;
    if (tsmLv > 0 && wType === 'two_hand_sword') {
        bonuses.bonusATK += tsmLv * 4;
    }
    // Increase HP Recovery (102): +5 HP per regen tick per level
    const hprLv = learned[102] || 0;
    if (hprLv > 0) bonuses.hpRegenBonus = hprLv * 5;

    // Moving HP Recovery (107): allow HP regen while moving
    const mhrLv = learned[107] || 0;
    if (mhrLv > 0) bonuses.movingHPRecovery = true;

    // Fatal Blow (109): stun chance on Bash = 5% per level
    const fbLv = learned[109] || 0;
    if (fbLv > 0) bonuses.fatalBlowChance = fbLv * 5;

    // Increase SP Recovery (204): +3 SP per regen tick per level
    const sprLv = learned[204] || 0;
    if (sprLv > 0) bonuses.spRegenBonus = sprLv * 3;

    // Owl's Eye (300): +1 DEX per level
    const oeLv = learned[300] || 0;
    if (oeLv > 0) bonuses.bonusDEX += oeLv;

    // Vulture's Eye (301/1706): +1 HIT per level, +1 cell range per level (bows only) (Archer & Rogue — non-stacking, use higher)
    const veLv = Math.max(learned[301] || 0, learned[1706] || 0);
    if (veLv > 0) {
        bonuses.bonusHIT += veLv;
        if (wType === 'bow') bonuses.bonusRange += veLv * 50; // 1 cell = 50 UE units
    }

    // Plagiarism (1714): +1% ASPD per level (passive bonus — iRO Wiki confirmed)
    const plagLv = learned[1714] || 0;
    if (plagLv > 0) {
        bonuses.aspdPercentBonus = (bonuses.aspdPercentBonus || 0) + plagLv;
    }

    // Divine Protection (401): DEF vs Undead/Demon race — rAthena battle.cpp:
    // vit_def += (int32)(((float)BaseLv / 25.0 + 3.0) * SkillLv + 0.5)
    const dpLv = learned[401] || 0;
    if (dpLv > 0) {
        const dpBaseLv = player.stats?.level || player.stats?.base_level || 1;
        const dpBonus = Math.floor((dpBaseLv / 25 + 3) * dpLv + 0.5);
        bonuses.raceDEF.undead = (bonuses.raceDEF.undead || 0) + dpBonus;
        bonuses.raceDEF.demon = (bonuses.raceDEF.demon || 0) + dpBonus;
    }

    // Demon Bane (413): ATK vs Undead/Demon race — rAthena battle.cpp:
    // damage += (decltype)(SkillLv * (BaseLv / 20.0 + 3.0))
    const dbLv = learned[413] || 0;
    if (dbLv > 0) {
        const dbBaseLv = player.stats?.level || player.stats?.base_level || 1;
        const dbBonus = Math.floor(dbLv * (dbBaseLv / 20 + 3));
        bonuses.raceATK.undead = (bonuses.raceATK.undead || 0) + dbBonus;
        bonuses.raceATK.demon = (bonuses.raceATK.demon || 0) + dbBonus;
    }

    // Double Attack (500): 5% chance per level to double-hit (daggers only)
    const daLv = learned[500] || 0;
    if (daLv > 0 && wType === 'dagger') {
        bonuses.doubleAttackChance = daLv * 5;
    }

    // Improve Dodge (501): +3 FLEE per level
    const idLv = learned[501] || 0;
    if (idLv > 0) bonuses.bonusFLEE += idLv * 3;

    // Advanced Book (1400): +3 ATK/lv with Books (Sage passive)
    const abLv = learned[1400] || 0;
    if (abLv > 0 && wType === 'book') {
        bonuses.bonusATK += abLv * 3;
        bonuses.bookAspdBonus = abLv * 0.5;
    }

    // Free Cast (1405): move while casting (Sage passive) — flag for cast interrupt check
    const fcLv = learned[1405] || 0;
    if (fcLv > 0) {
        bonuses.freeCastLevel = fcLv;
    }

    // Dragonology (1407): INT bonus + Dragon ATK/resist (Sage passive)
    const dragLv = learned[1407] || 0;
    if (dragLv > 0) {
        bonuses.bonusINT = (bonuses.bonusINT || 0) + [1, 1, 2, 2, 3][dragLv - 1];
        const dragonPct = dragLv * 4;
        if (!bonuses.raceATK) bonuses.raceATK = {};
        bonuses.raceATK.dragon = (bonuses.raceATK.dragon || 0) + dragonPct;
        if (!bonuses.raceResist) bonuses.raceResist = {};
        bonuses.raceResist.dragon = (bonuses.raceResist.dragon || 0) + dragonPct;
        if (!bonuses.raceMATK) bonuses.raceMATK = {};
        bonuses.raceMATK.dragon = (bonuses.raceMATK.dragon || 0) + (dragLv * 2);
    }

    // Faith (1300): +200 MaxHP/lv, +5% holy resistance/lv (Crusader passive)
    const faithLv = learned[1300] || 0;
    if (faithLv > 0) {
        bonuses.bonusMaxHp = (bonuses.bonusMaxHp || 0) + faithLv * 200;
        bonuses.holyResist = faithLv * 5;
    }

    // Katar Mastery (1100): +3 ATK/level with Katars
    const kmLv = learned[1100] || 0;
    if (kmLv > 0 && wType === 'katar') {
        bonuses.bonusATK += kmLv * 3;
        bonuses.katarMasteryATK = kmLv * 3;
    }

    // Righthand Mastery (1107): dual wield right-hand penalty recovery (passive, Assassin)
    const rhmLv = learned[1107] || 0;
    if (rhmLv > 0) bonuses.rightHandMasteryLv = rhmLv;

    // Lefthand Mastery (1108): dual wield left-hand penalty recovery (passive, Assassin)
    const lhmLv = learned[1108] || 0;
    if (lhmLv > 0) bonuses.leftHandMasteryLv = lhmLv;

    // Spear Mastery (700): +4 ATK/level with spears (+5/lv when mounted)
    const spMasLv = learned[700] || 0;
    const wSubType = player.equippedWeaponRight?.subType || '';
    if (spMasLv > 0 && (wType === 'spear' || wSubType === '1hSpear' || wSubType === '2hSpear')) {
        const perLevel = player.isMounted ? 5 : 4;
        bonuses.bonusATK += spMasLv * perLevel;
        bonuses.spearMasteryLv = spMasLv;
    }

    // Cavalry Mastery (709): restores mounted ASPD penalty (passive, Knight/Crusader)
    const cavMasLv = learned[709] || 0;
    if (cavMasLv > 0) bonuses.cavalierMasteryLv = cavMasLv;

    // Mace Mastery (1008): +3 ATK/level with maces (Priest)
    const mmLv = learned[1008] || 0;
    if (mmLv > 0 && wType === 'mace') {
        bonuses.bonusATK += mmLv * 3;
    }

    // Increase SP Recovery - Priest (1016): +3 SP per regen tick per level
    const spRecPriestLv = learned[1016] || 0;
    if (spRecPriestLv > 0) bonuses.spRegenBonus += spRecPriestLv * 3;

    // Beast Bane (915): +4 ATK/level vs Brute and Insect race (Hunter)
    const bbLv = learned[915] || 0;
    if (bbLv > 0) {
        bonuses.raceATK.brute = (bonuses.raceATK.brute || 0) + bbLv * 4;
        bonuses.raceATK.insect = (bonuses.raceATK.insect || 0) + bbLv * 4;
    }

    // Iron Fists (1600): +3 ATK/level with knuckle/bare hand (Monk)
    const ifLv = learned[1600] || 0;
    if (ifLv > 0 && (wType === 'knuckle' || wType === 'fist' || wType === 'bare_hand' || !wType)) {
        bonuses.bonusATK += ifLv * 3;
    }

    // Dodge (1608): +FLEE per level, floor(1.5*lv) (Monk)
    const dodgeLv = learned[1608] || 0;
    if (dodgeLv > 0) {
        bonuses.bonusFLEE += Math.floor(1.5 * dodgeLv);
    }

    // Music Lessons (1500): +3 ATK/level with instruments (Bard)
    const mlLv = learned[1500] || 0;
    if (mlLv > 0 && wType === 'instrument') {
        bonuses.bonusATK += mlLv * 3;
    }

    // Dance Lessons (1520): +3 ATK/level with whips (Dancer)
    const dlLv = learned[1520] || 0;
    if (dlLv > 0 && wType === 'whip') {
        bonuses.bonusATK += dlLv * 3;
    }

    // Weaponry Research (1204): +2 ATK/level (ALL weapons), +2 HIT/level (Blacksmith)
    const wrLv = learned[1204] || 0;
    if (wrLv > 0) {
        bonuses.bonusATK += wrLv * 2;
        bonuses.bonusHIT += wrLv * 2;
    }

    // Hilt Binding (1207): +1 STR, +4 ATK, +10% duration to AR/WP/PT (Blacksmith)
    const hbLv = learned[1207] || 0;
    if (hbLv > 0) {
        bonuses.bonusSTR = (bonuses.bonusSTR || 0) + 1;
        bonuses.bonusATK += 4;
        bonuses.hiltBindingDurationBonus = true;
    }

    // Skin Tempering (1205): +4% fire resist/lv, +1% neutral resist/lv (Blacksmith)
    const stLv = learned[1205] || 0;
    if (stLv > 0) {
        bonuses.elementResist = bonuses.elementResist || {};
        bonuses.elementResist.fire = (bonuses.elementResist.fire || 0) + stLv * 4;
        bonuses.elementResist.neutral = (bonuses.elementResist.neutral || 0) + stLv;
    }

    // Alchemist Axe Mastery (1804): +3 ATK/lv with Axes (mastery ATK)
    const alchAxeLv = learned[1804] || 0;
    if (alchAxeLv > 0) {
        const wt = player.equippedWeaponRight?.weaponType || player.weaponType || '';
        if (['axe', 'one_hand_axe', 'two_hand_axe'].includes(wt)) {
            bonuses.bonusATK += alchAxeLv * 3;
        }
    }

    // Potion Research (1805): +5% potion heal/lv, +1% brew rate/lv
    const potResLv = learned[1805] || 0;
    if (potResLv > 0) {
        bonuses.potionHealBonus = (bonuses.potionHealBonus || 0) + potResLv * 5;
        bonuses.brewRateBonus = (bonuses.brewRateBonus || 0) + potResLv;
    }

    return bonuses;
}

// Check skill cooldown
function isSkillOnCooldown(player, skillId) {
    const cd = (player.skillCooldowns || {})[skillId];
    if (!cd) return false;
    return Date.now() < cd;
}

// Get remaining cooldown ms
function getSkillCooldownRemaining(player, skillId) {
    const cd = (player.skillCooldowns || {})[skillId];
    if (!cd) return 0;
    return Math.max(0, cd - Date.now());
}

// Set a skill cooldown
function setSkillCooldown(player, skillId, cooldownMs) {
    if (!player.skillCooldowns) player.skillCooldowns = {};
    player.skillCooldowns[skillId] = Date.now() + cooldownMs;
}

// Set After-Cast Delay (global skill lockout) + per-skill cooldown + emit events
function applySkillDelays(characterId, player, skillId, levelData, socket) {
    const cooldownMs = levelData.cooldown || 0;
    const acdMs = levelData.afterCastDelay || 0;

    // Per-skill cooldown (only THIS skill is locked)
    if (cooldownMs > 0) {
        setSkillCooldown(player, skillId, cooldownMs);
        if (socket) socket.emit('skill:cooldown_started', { skillId, cooldownMs });
    }

    // After-Cast Delay (ALL skills locked globally)
    // Phase 1: Card delay rate modifier (bDelayRate: negative = faster, e.g., Kiel -30%)
    let effectiveAcd = acdMs;
    if (acdMs > 0 && player.cardDelayRate) {
        effectiveAcd = Math.max(0, Math.floor(acdMs * (100 + player.cardDelayRate) / 100));
    }
    // Bragi (Poem of Bragi): reduce ACD by % — Phase 4
    if (effectiveAcd > 0) {
        const bragiMods = getCombinedModifiers(player);
        if (bragiMods.bragiAcdReduction > 0) {
            effectiveAcd = Math.max(0, Math.floor(effectiveAcd * (100 - bragiMods.bragiAcdReduction) / 100));
        }
    }
    if (effectiveAcd > 0) {
        afterCastDelayEnd.set(characterId, Date.now() + effectiveAcd);
        if (socket) socket.emit('skill:acd_started', { afterCastDelay: effectiveAcd });
    }
}

// ============================================================
// Performance System (Bard/Dancer Songs & Dances) — Phase 4
// ============================================================

const PERFORMANCE_CONSTANTS = {
    SOLO_AOE_RADIUS: 175,         // 7x7 cells = 3.5 cells * 50 UE/cell
    ENSEMBLE_AOE_RADIUS: 225,     // 9x9 cells = 4.5 * 50
    EFFECT_LINGER_DURATION: 20000, // 20s buff linger after leaving AoE
    TICK_INTERVAL: 1000,           // Check AoE + drain SP every 1 second
};

// SP drain intervals per song/dance (ms between 1 SP drain ticks from caster)
const SONG_SP_DRAIN = {
    'a_whistle': 5000,
    'assassin_cross_of_sunset': 3000,
    'poem_of_bragi': 5000,
    'apple_of_idun': 6000,
    'dissonance': 3000,
    'humming': 5000,
    'fortunes_kiss': 4000,
    'service_for_you': 5000,
    'please_dont_forget_me': 10000,
    'ugly_dance': 3000,
};

// Map skill name to the buff it applies (null = damage-only, no lingering buff)
const PERFORMANCE_BUFF_MAP = {
    'a_whistle': 'song_whistle',
    'assassin_cross_of_sunset': 'song_assassin_cross',
    'poem_of_bragi': 'song_bragi',
    'apple_of_idun': 'song_apple_of_idun',
    'humming': 'dance_humming',
    'fortunes_kiss': 'dance_fortune_kiss',
    'service_for_you': 'dance_service_for_you',
    'please_dont_forget_me': 'dance_pdfm',
    'ugly_dance': 'dance_ugly',
    'dissonance': null,            // Damage only, MISC type
};

// Which performances are "offensive" (debuff enemies) vs "supportive" (buff allies)
const OFFENSIVE_PERFORMANCES = new Set([
    'dissonance', 'please_dont_forget_me', 'ugly_dance',
]);

// ============================================================
// Ensemble System (Bard + Dancer cooperative performances)
// ============================================================

// Active ensembles map: ensembleId → ensemble state object
const activeEnsembles = new Map();

// SP drain intervals per ensemble (ms between 1 SP drain ticks from EACH performer)
const ENSEMBLE_SP_DRAIN = {
    'lullaby': 4000,
    'mr_kim_a_rich_man': 3000,
    'eternal_chaos': 4000,
    'drum_on_battlefield': 5000,
    'ring_of_nibelungen': 3000,
    'lokis_veil': 4000,
    'into_the_abyss': 5000,
    'invulnerable_siegfried': 3000,
};

// Ensemble effect types and tick configurations
const ENSEMBLE_EFFECTS = {
    'lullaby': { type: 'sleep_aoe', tickInterval: 6000, sleepDuration: 30000 },
    'mr_kim_a_rich_man': { type: 'exp_bonus' },
    'eternal_chaos': { type: 'vit_def_zero' },
    'drum_on_battlefield': { type: 'atk_def_buff' },
    'ring_of_nibelungen': { type: 'lv4_weapon_atk' },
    'lokis_veil': { type: 'skill_block' },
    'into_the_abyss': { type: 'no_catalysts' },
    'invulnerable_siegfried': { type: 'element_status_resist' },
};

// Map ensemble skill name variants (Bard/Dancer have different skill names for same ensemble)
// to a canonical ensemble name for effect lookup
const ENSEMBLE_CANONICAL_NAME = {
    'lullaby': 'lullaby', 'lullaby_dancer': 'lullaby',
    'mr_kim_a_rich_man': 'mr_kim_a_rich_man', 'mr_kim_dancer': 'mr_kim_a_rich_man',
    'eternal_chaos': 'eternal_chaos', 'eternal_chaos_dancer': 'eternal_chaos',
    'drum_on_battlefield': 'drum_on_battlefield', 'drum_battlefield_dancer': 'drum_on_battlefield',
    'ring_of_nibelungen': 'ring_of_nibelungen', 'nibelungen_dancer': 'ring_of_nibelungen',
    'lokis_veil': 'lokis_veil', 'lokis_veil_dancer': 'lokis_veil',
    'into_the_abyss': 'into_the_abyss', 'into_abyss_dancer': 'into_the_abyss',
    'invulnerable_siegfried': 'invulnerable_siegfried', 'siegfried_dancer': 'invulnerable_siegfried',
};

// Bard class set for ensemble partner matching
const BARD_CLASSES = new Set(['bard', 'minstrel', 'clown']);
const DANCER_CLASSES = new Set(['dancer', 'gypsy']);

/**
 * Check if a player is currently performing a song/dance.
 */
function isPerforming(player) {
    return player.performanceState !== null && player.performanceState !== undefined;
}

/**
 * Calculate performance effect values based on caster stats and skill level.
 * Returns skill-specific effect object for the buff.
 */
function calculatePerformanceEffects(player, skillName, skillLevel) {
    const stats = getEffectiveStats(player);
    const musicLv = (player.learnedSkills && player.learnedSkills[1500]) || 0; // Music Lessons
    const danceLv = (player.learnedSkills && player.learnedSkills[1520]) || 0; // Dance Lessons
    const lessonsLv = musicLv || danceLv; // Whichever is non-zero

    switch (skillName) {
        case 'a_whistle':
            return {
                fleeBonus: skillLevel + Math.floor(stats.agi / 10) + Math.floor(lessonsLv * 0.5),
                perfectDodgeBonus: Math.floor((skillLevel + 1) / 2) + Math.floor(stats.luk / 30) + Math.floor(lessonsLv * 0.2),
            };
        case 'assassin_cross_of_sunset':
            return {
                aspdBonus: 10 + skillLevel + Math.floor(stats.agi / 20) + Math.floor(lessonsLv / 2),
            };
        case 'poem_of_bragi':
            return {
                castReduction: skillLevel * 3 + Math.floor(stats.dex / 10) + lessonsLv,
                acdReduction: (skillLevel < 10 ? skillLevel * 3 : 50) + Math.floor(stats.int / 5) + lessonsLv * 2,
            };
        case 'apple_of_idun':
            return {
                maxHpPercent: 5 + skillLevel * 2 + Math.floor(stats.vit / 10) + Math.floor(lessonsLv / 2),
                hpPerTick: (30 + skillLevel * 5) + Math.floor(stats.vit / 2) + lessonsLv * 5,
            };
        case 'humming':
            // eathena: val1 = 2*skilllv + status->dex/10 + DanceLessonsLv
            return {
                hitBonus: (skillLevel * 2) + Math.floor(stats.dex / 10) + lessonsLv,
            };
        case 'fortunes_kiss':
            // eathena: val1 = (10 + skilllv + luk/10 + DL) * 10 — +10 base constant, display = val1/10
            return {
                critBonus: 10 + skillLevel + Math.floor(stats.luk / 10) + lessonsLv,
            };
        case 'service_for_you':
            // eathena: val1 = 15 + skilllv + int/10 + DL; val2 = 20 + 3*skilllv + int/10 + DL
            return {
                maxSpPercent: 15 + skillLevel + Math.floor(stats.int / 10) + lessonsLv,
                spCostReduction: 20 + (skillLevel * 3) + Math.floor(stats.int / 10) + lessonsLv,
            };
        case 'please_dont_forget_me':
            // eathena: val1 = dex/10 + 3*skilllv + 5 + DL; val2 = agi/10 + 3*skilllv + 5 + DL
            return {
                aspdReduction: 5 + (skillLevel * 3) + Math.floor(stats.dex / 10) + lessonsLv,
                moveSpeedReduction: 5 + (skillLevel * 3) + Math.floor(stats.agi / 10) + lessonsLv,
            };
        case 'ugly_dance':
            // eathena: rate = 5+5*skilllv; if(DL>0) rate += 5+DL
            return {
                spDrainPerTick: (5 + 5 * skillLevel) + (lessonsLv > 0 ? 5 + lessonsLv : 0),
            };
        case 'dissonance':
            return {
                damagePerTick: 30 + 10 * skillLevel + lessonsLv * 3,
            };
        default:
            return {};
    }
}

/**
 * Start a performance (song/dance). Creates ground effect and sets player state.
 * Returns true on success, false on failure.
 */
function startPerformance(characterId, player, skillId, skillName, skillLevel, spCost, socket) {
    const zone = player.zone || 'prontera_south';
    const now = Date.now();

    // Calculate effect values
    const effectValues = calculatePerformanceEffects(player, skillName, skillLevel);
    const spDrainInterval = SONG_SP_DRAIN[skillName] || 5000;
    const skill = SKILL_MAP.get(skillId);
    const duration = (skill && skill.levels[skillLevel - 1]) ? skill.levels[skillLevel - 1].duration : 180000;

    // Determine performance type
    const isBard = (player.jobClass === 'bard' || player.jobClass === 'clown');
    const performanceType = isBard ? 'song' : 'dance';
    const lessonsLv = isBard
        ? ((player.learnedSkills && player.learnedSkills[1500]) || 0)
        : ((player.learnedSkills && player.learnedSkills[1520]) || 0);

    // Create ground effect (centered on caster, moves with them)
    const geId = createGroundEffect({
        type: skillName,
        category: 'performance',
        skillId,
        skillLevel,
        casterId: characterId,
        casterName: player.characterName,
        zone,
        x: player.lastX || 0,
        y: player.lastY || 0,
        z: player.lastZ || 0,
        radius: PERFORMANCE_CONSTANTS.SOLO_AOE_RADIUS,
        duration,
        hitsRemaining: -1,
    });

    // Deduct initial SP
    player.mana = Math.max(0, player.mana - spCost);

    // Set performance state
    const spDrainAmount = 1;

    player.performanceState = {
        skillId,
        skillName,
        skillLevel,
        startedAt: now,
        expiresAt: now + duration,
        spDrainInterval,
        spDrainAmount,
        lastSpDrainTime: now,
        lastEffectTickTime: now,
        groundEffectId: geId,
        lessonsLv,
        effectValues,
        buffName: PERFORMANCE_BUFF_MAP[skillName] || null,
    };
    player.lastPerformanceSkillId = skillId;
    player.lastPerformanceLevel = skillLevel; // BUG10: store level for Encore
    player.performanceType = performanceType;

    // RO Classic: performance movement speed = (25 + 2.5 * LessonsLv)% of normal (Bug #7)
    // Base: 25% (1/4 speed), max 50% at Lv10. Ensembles: 0% (cannot move).
    player.performanceMoveSpeedMultiplier = (25 + 2.5 * lessonsLv) / 100;

    // Broadcast performance:start to zone
    broadcastToZone(zone, 'performance:start', {
        characterId,
        characterName: player.characterName,
        skillId,
        skillName: skill ? skill.displayName : skillName,
        skillLevel,
        position: { x: player.lastX || 0, y: player.lastY || 0, z: player.lastZ || 0 },
        radius: PERFORMANCE_CONSTANTS.SOLO_AOE_RADIUS,
        performanceType,
    });

    // Emit skill:used and health_update to caster
    if (socket) {
        socket.emit('skill:used', {
            skillId, skillName: skill ? skill.displayName : skillName,
            level: skillLevel, spCost, remainingMana: player.mana, maxMana: player.maxMana
        });
        socket.emit('combat:health_update', {
            characterId, health: player.health, maxHealth: player.maxHealth,
            mana: player.mana, maxMana: player.maxMana
        });
    }

    logger.info(`[PERFORMANCE] ${player.characterName} started ${skillName} Lv${skillLevel} (${performanceType})`);
    return true;
}

/**
 * Cancel an active performance. Cleans up ground effect and player state.
 * @param {string} reason - 'adaptation', 'sp_depleted', 'cc', 'death', 'weapon_swap', 'skill_reset', 'disconnect'
 */
function cancelPerformance(characterId, player, reason) {
    if (!player.performanceState) return;

    const zone = player.zone || 'prontera_south';
    const perf = player.performanceState;

    // Remove ground effect
    if (perf.groundEffectId) {
        removeGroundEffect(perf.groundEffectId);
        broadcastToZone(zone, 'skill:ground_effect_removed', {
            effectId: perf.groundEffectId, type: perf.skillName, reason,
        });
    }

    // Clear performance state
    player.performanceState = null;
    player.performanceType = null;
    player.performanceMoveSpeedMultiplier = null; // Restore full movement speed

    // Broadcast performance:stop
    broadcastToZone(zone, 'performance:stop', {
        characterId, reason,
    });

    logger.info(`[PERFORMANCE] ${player.characterName} stopped performing (reason: ${reason})`);
}

/**
 * End an active ensemble. Cleans up both performers, ground effect, and applies aftermath.
 * @param {string} ensembleId - The ensemble's unique ID
 * @param {object} ens - The ensemble state object
 * @param {string} [reason] - 'expired', 'adaptation', 'cc', 'death', 'disconnect', 'sp_depleted'
 */
function endEnsemble(ensembleId, ens, reason) {
    if (!ens || !activeEnsembles.has(ensembleId)) return;

    const caster = connectedPlayers.get(ens.casterId);
    const partner = connectedPlayers.get(ens.partnerId);

    // Clean up caster state
    if (caster) {
        caster.isPerformingEnsemble = false;
        caster.ensembleState = null;
        caster.performanceMoveSpeedMultiplier = null; // Restore full movement speed
        // RO Classic: 10s aftermath debuff (cannot use skills, reduced movement)
        applyBuff(caster, {
            name: 'ensemble_aftermath', skillId: ens.skillId,
            casterId: ens.casterId, casterName: ens.casterName,
            duration: 10000, noSkills: true, moveSpeedReduction: 50,
        });
        broadcastToZone(ens.zone, 'skill:buff_applied', {
            targetId: ens.casterId, targetName: ens.casterName, isEnemy: false,
            casterId: ens.casterId, casterName: ens.casterName, skillId: ens.skillId,
            buffName: 'ensemble_aftermath', duration: 10000, effects: { noSkills: true, moveSpeedReduction: 50 },
        });
        // Emit stats so client sees aftermath move speed reduction
        const cEffStats = getEffectiveStats(caster);
        const cDerived = roDerivedStats(cEffStats);
        const cSock = io.sockets.sockets.get(caster.socketId);
        if (cSock) {
            cSock.emit('player:stats', buildFullStatsPayload(ens.casterId, caster, cEffStats, cDerived, Math.min(COMBAT.ASPD_CAP, cDerived.aspd + (caster.weaponAspdMod || 0))));
        }
    }

    // Clean up partner state
    if (partner) {
        partner.isPerformingEnsemble = false;
        partner.ensembleState = null;
        partner.performanceMoveSpeedMultiplier = null;
        applyBuff(partner, {
            name: 'ensemble_aftermath', skillId: ens.skillId,
            casterId: ens.partnerId, casterName: ens.partnerName,
            duration: 10000, noSkills: true, moveSpeedReduction: 50,
        });
        broadcastToZone(ens.zone, 'skill:buff_applied', {
            targetId: ens.partnerId, targetName: ens.partnerName, isEnemy: false,
            casterId: ens.partnerId, casterName: ens.partnerName, skillId: ens.skillId,
            buffName: 'ensemble_aftermath', duration: 10000, effects: { noSkills: true, moveSpeedReduction: 50 },
        });
        const pEffStats = getEffectiveStats(partner);
        const pDerived = roDerivedStats(pEffStats);
        const pSock = io.sockets.sockets.get(partner.socketId);
        if (pSock) {
            pSock.emit('player:stats', buildFullStatsPayload(ens.partnerId, partner, pEffStats, pDerived, Math.min(COMBAT.ASPD_CAP, pDerived.aspd + (partner.weaponAspdMod || 0))));
        }
    }

    // Remove ground effect
    if (ens.groundEffectId) {
        removeGroundEffect(ens.groundEffectId);
        broadcastToZone(ens.zone, 'skill:ground_effect_removed', {
            effectId: ens.groundEffectId, type: ens.skillName, reason: reason || 'ended',
        });
    }

    // Clear Eternal Chaos VIT-DEF-zero flags on enemies in this zone
    if (ens.effectType === 'vit_def_zero') {
        for (const [eid, enemy] of enemies.entries()) {
            if ((enemy.zone || 'prontera_south') === ens.zone) {
                delete enemy._ensembleVitDefZero;
            }
        }
    }

    // Remove from active ensembles
    activeEnsembles.delete(ensembleId);

    // Broadcast ensemble end to zone
    broadcastToZone(ens.zone, 'skill:ensemble_end', {
        ensembleId, skillName: ens.skillName, reason: reason || 'ended',
    });

    logger.info(`[ENSEMBLE] ${ens.casterName} + ${ens.partnerName} ${ens.skillDisplayName || ens.skillName} ended (reason: ${reason || 'ended'})`);
}

/**
 * Emit buff icon + stats update when an ensemble buff is first applied to a player.
 * Shared helper for all 5 ensemble buff types to avoid duplication.
 */
function emitEnsembleBuffStats(pid, ally, buffName, ens, zone) {
    const buffConfig = BUFF_TYPES[buffName];
    broadcastToZone(zone, 'skill:buff_applied', {
        targetId: pid, targetName: ally.characterName, isEnemy: false,
        casterId: ens.casterId, casterName: ens.casterName,
        skillId: ens.skillId,
        buffName: buffConfig ? buffConfig.displayName : buffName,
        duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
    });
    const effStats = getEffectiveStats(ally);
    const derived = roDerivedStats(effStats);
    const aspd = Math.min(COMBAT.ASPD_CAP, derived.aspd + (ally.weaponAspdMod || 0));
    ally.maxHealth = derived.maxHP;
    ally.maxMana = derived.maxSP;
    const sock = io.sockets.sockets.get(ally.socketId);
    if (sock) {
        sock.emit('player:stats', buildFullStatsPayload(pid, ally, effStats, derived, aspd));
        sock.emit('combat:health_update', {
            characterId: pid, health: ally.health,
            maxHealth: ally.maxHealth, mana: ally.mana, maxMana: ally.maxMana
        });
    }
}

/**
 * Process ensemble effect tick. Called once per tick for each active ensemble.
 * Different ensemble types have different tick intervals and effects.
 */
function processEnsembleEffect(ens, now) {
    const tickInterval = ens.effectTickInterval || 1000;
    if (now - ens.lastTickTime < tickInterval) return;
    ens.lastTickTime = now;

    const ensZone = ens.zone || 'prontera_south';

    switch (ens.effectType) {
        case 'sleep_aoe': {
            // Lullaby: Apply sleep to enemies in AoE every 6s
            const sleepSource = connectedPlayers.get(ens.casterId) || null;
            for (const [eid, enemy] of enemies.entries()) {
                if (enemy.isDead) continue;
                if ((enemy.zone || 'prontera_south') !== ensZone) continue;
                if (enemy.template && enemy.template.isBoss) continue; // Boss immune
                const dx = enemy.x - ens.x, dy = enemy.y - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;
                // Apply sleep status (30% base chance, 30s duration — resisted by INT/MDEF)
                if (typeof applyStatusEffect === 'function' && sleepSource) {
                    applyStatusEffect(sleepSource, enemy, 'sleep', 30, 30000);
                }
            }
            // Also affect players in AoE (PvP/friendly fire per RO Classic)
            for (const [pid, p] of connectedPlayers.entries()) {
                if (p.zone !== ens.zone || p.isDead) continue;
                if (pid === ens.casterId || pid === ens.partnerId) continue; // Casters immune
                if (p.partyId === ens.casterPartyId) continue; // Party members immune in PvE
                const dx = p.x - ens.x, dy = p.y - ens.y;
                if (Math.sqrt(dx*dx + dy*dy) <= ens.radius) {
                    if (sleepSource) applyStatusEffect(pid, p, 'sleep', 30, 30000, ens.zone, sleepSource);
                }
            }
            break;
        }

        case 'vit_def_zero': {
            // Eternal Chaos: Set VIT-derived DEF to zero for enemies in AoE
            for (const [eid, enemy] of enemies.entries()) {
                if (enemy.isDead) continue;
                if ((enemy.zone || 'prontera_south') !== ensZone) continue;
                const dx = enemy.x - ens.x, dy = enemy.y - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) <= ens.radius) {
                    enemy._ensembleVitDefZero = true;
                } else {
                    // Clear flag for enemies that leave the AoE
                    delete enemy._ensembleVitDefZero;
                }
            }
            break;
        }

        case 'atk_def_buff': {
            // Drum on the Battlefield: +ATK and +DEF for party members in AoE
            const atkBonus = 25 + 25 * ens.level;   // +50/75/100/125/150
            const defBonus = 2 + 2 * ens.level;     // +4/6/8/10/12
            const caster = connectedPlayers.get(ens.casterId);
            const casterPartyId = caster ? caster.partyId : null;

            for (const [pid, ally] of connectedPlayers.entries()) {
                if (ally.isDead) continue;
                if ((ally.zone || 'prontera_south') !== ensZone) continue;
                if (!casterPartyId || ally.partyId !== casterPartyId) continue;
                const ax = ally.lastX || 0, ay = ally.lastY || 0;
                const dx = ax - ens.x, dy = ay - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;

                const isNew = !hasBuff(ally, 'ensemble_drum');
                applyBuff(ally, {
                    name: 'ensemble_drum', skillId: ens.skillId,
                    casterId: ens.casterId, casterName: ens.casterName,
                    duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
                    atkBonus, defBonus,
                });
                if (isNew) emitEnsembleBuffStats(pid, ally, 'ensemble_drum', ens, ensZone);
            }
            break;
        }

        case 'lv4_weapon_atk': {
            // Ring of Nibelungen: +ATK for characters with Lv4 weapons in AoE
            const atkBonus = 50 + 25 * ens.level; // +75/100/125/150/175
            const caster = connectedPlayers.get(ens.casterId);
            const casterPartyId = caster ? caster.partyId : null;

            for (const [pid, ally] of connectedPlayers.entries()) {
                if (ally.isDead) continue;
                if ((ally.zone || 'prontera_south') !== ensZone) continue;
                if (!casterPartyId || ally.partyId !== casterPartyId) continue;
                if (!ally.equippedWeaponRight || ally.equippedWeaponRight.weaponLevel !== 4) continue;
                const ax = ally.lastX || 0, ay = ally.lastY || 0;
                const dx = ax - ens.x, dy = ay - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;

                const isNew = !hasBuff(ally, 'ensemble_nibelungen');
                applyBuff(ally, {
                    name: 'ensemble_nibelungen', skillId: ens.skillId,
                    casterId: ens.casterId, casterName: ens.casterName,
                    duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
                    atkBonus,
                });
                if (isNew) emitEnsembleBuffStats(pid, ally, 'ensemble_nibelungen', ens, ensZone);
            }
            break;
        }

        case 'exp_bonus': {
            // Mr. Kim A Rich Man: +EXP buff for party members in AoE
            // effectValue = 25 + 11 * level = 36/47/58/69/80
            const expBonusPct = ens.effectValue || (25 + 11 * ens.level);
            const caster = connectedPlayers.get(ens.casterId);
            const casterPartyId = caster ? caster.partyId : null;

            for (const [pid, ally] of connectedPlayers.entries()) {
                if (ally.isDead) continue;
                if ((ally.zone || 'prontera_south') !== ensZone) continue;
                if (!casterPartyId || ally.partyId !== casterPartyId) continue;
                const ax = ally.lastX || 0, ay = ally.lastY || 0;
                const dx = ax - ens.x, dy = ay - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;

                const isNew = !hasBuff(ally, 'ensemble_mr_kim');
                applyBuff(ally, {
                    name: 'ensemble_mr_kim', skillId: ens.skillId,
                    casterId: ens.casterId, casterName: ens.casterName,
                    duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
                    expBonusPct,
                });
                if (isNew) emitEnsembleBuffStats(pid, ally, 'ensemble_mr_kim', ens, ensZone);
            }
            break;
        }

        case 'element_status_resist': {
            // Invulnerable Siegfried: element + status resist for party members in AoE
            // Use skill data effectValue (55+5*lv = 60/65/70/75/80%) for non-Neutral element resist
            const elementResistPct = ens.effectValue || (55 + 5 * ens.level);
            const statusResist = ens.statusResist || (ens.level * 10);  // 10/20/30/40/50%
            // Build per-element resist object (all 9 non-Neutral elements)
            const elementResist = {};
            ['fire', 'water', 'earth', 'wind', 'poison', 'holy', 'dark', 'ghost', 'undead'].forEach(el => {
                elementResist[el] = elementResistPct;
            });
            const caster = connectedPlayers.get(ens.casterId);
            const casterPartyId = caster ? caster.partyId : null;

            for (const [pid, ally] of connectedPlayers.entries()) {
                if (ally.isDead) continue;
                if ((ally.zone || 'prontera_south') !== ensZone) continue;
                if (!casterPartyId || ally.partyId !== casterPartyId) continue;
                const ax = ally.lastX || 0, ay = ally.lastY || 0;
                const dx = ax - ens.x, dy = ay - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;

                const isNew = !hasBuff(ally, 'ensemble_siegfried');
                applyBuff(ally, {
                    name: 'ensemble_siegfried', skillId: ens.skillId,
                    casterId: ens.casterId, casterName: ens.casterName,
                    duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
                    elementResist, statusResist,
                });
                if (isNew) emitEnsembleBuffStats(pid, ally, 'ensemble_siegfried', ens, ensZone);
            }
            break;
        }

        case 'no_catalysts': {
            // Into the Abyss: no gemstone cost for party members in AoE
            const caster = connectedPlayers.get(ens.casterId);
            const casterPartyId = caster ? caster.partyId : null;

            for (const [pid, ally] of connectedPlayers.entries()) {
                if (ally.isDead) continue;
                if ((ally.zone || 'prontera_south') !== ensZone) continue;
                if (!casterPartyId || ally.partyId !== casterPartyId) continue;
                const ax = ally.lastX || 0, ay = ally.lastY || 0;
                const dx = ax - ens.x, dy = ay - ens.y;
                if (Math.sqrt(dx * dx + dy * dy) > ens.radius) continue;

                const isNew = !hasBuff(ally, 'ensemble_into_abyss');
                applyBuff(ally, {
                    name: 'ensemble_into_abyss', skillId: ens.skillId,
                    casterId: ens.casterId, casterName: ens.casterName,
                    duration: PERFORMANCE_CONSTANTS.EFFECT_LINGER_DURATION,
                    noGemStone: true,
                });
                if (isNew) emitEnsembleBuffStats(pid, ally, 'ensemble_into_abyss', ens, ensZone);
            }
            break;
        }

        case 'skill_block': {
            // Loki's Veil: skill blocking is checked in skill:use handler
            // No per-tick action needed — the blocking check reads activeEnsembles directly
            break;
        }

        case 'movement_barrier': {
            // Moonlit Water Mill: movement barrier — attack blocking checked in combat tick
            // No per-tick action needed here
            break;
        }

        default:
            break;
    }
}

// Apply a buff/debuff to a target (player or enemy)
// Delegates to the generic buff system module
function applyBuff(target, buffDef) {
    return applyBuffGeneric(target, buffDef);
}

// Remove expired buffs, returns array of expired buff objects
function expireBuffs(target) {
    return expireBuffsGeneric(target);
}

// Auto Berserk: dynamically toggle ATK bonus based on HP threshold (25%)
// Called whenever a player's HP changes (damage taken, heal received)
// Energy Coat: reduce physical damage based on current SP%, drain SP on hit
// RO Classic pre-renewal tiers:
//   SP  0-20%: -6% damage,  1.0% of damage drained from SP
//   SP 20-40%: -12% damage, 1.5% of damage drained from SP
//   SP 40-60%: -18% damage, 2.0% of damage drained from SP
//   SP 60-80%: -24% damage, 2.5% of damage drained from SP
//   SP 80-100%: -30% damage, 3.0% of damage drained from SP
// Returns the reduced damage amount. Only applies to physical damage.
function applyEnergyCoat(player, damage, characterId, zone) {
    if (!hasBuff(player, 'energy_coat')) return damage;
    if (player.maxMana <= 0 || player.mana <= 0) {
        // No SP left — dispel Energy Coat
        removeBuff(player, 'energy_coat');
        broadcastToZone(zone || 'prontera_south', 'skill:buff_removed', { targetId: characterId, isEnemy: false, buffName: 'energy_coat', reason: 'no_sp' });
        return damage;
    }

    const spRatio = player.mana / player.maxMana;
    // rAthena: per = floor((100*sp/maxsp - 1) / 20) → tier 0-4
    const tier = spRatio > 0.8 ? 4 : spRatio > 0.6 ? 3 : spRatio > 0.4 ? 2 : spRatio > 0.2 ? 1 : 0;
    const reduction = 0.06 * (1 + tier); // 6%, 12%, 18%, 24%, 30%

    const reducedDamage = Math.max(1, Math.floor(damage * (1 - reduction)));
    // rAthena: SP drain = (10 + 5*tier) * MaxSP / 1000 — MaxSP-based, NOT damage-based
    const spDrain = Math.max(1, Math.floor((10 + 5 * tier) * player.maxMana / 1000));
    player.mana = Math.max(0, player.mana - spDrain);

    // Dispel if SP drained to 0
    if (player.mana <= 0) {
        removeBuff(player, 'energy_coat');
        broadcastToZone(zone || 'prontera_south', 'skill:buff_removed', { targetId: characterId, isEnemy: false, buffName: 'energy_coat', reason: 'no_sp' });
    }

    return reducedDamage;
}

// Safety Wall check for melee physical skills (rAthena: BF_SHORT check in battle_calc_damage)
// Returns true if attack was blocked (damage absorbed by SW)
function checkSafetyWallBlock(target, zone, targetId, isEnemy) {
    if (typeof getGroundEffectsAtPosition !== 'function') return false;
    const x = isEnemy ? target.x : (target.lastX || 0);
    const y = isEnemy ? target.y : (target.lastY || 0);
    const z = isEnemy ? (target.z || 0) : (target.lastZ || 0);
    const effects = getGroundEffectsAtPosition(x, y, z, 100);
    const sw = effects.find(e => (e.type === 'safety_wall' || e.type === 'safety_wall_priest') && e.hitsRemaining > 0);
    if (sw) {
        sw.hitsRemaining--;
        if (sw.hitsRemaining <= 0 && typeof removeGroundEffect === 'function') removeGroundEffect(sw.id);
        broadcastToZone(zone, 'skill:effect_damage', {
            targetId, isEnemy, damage: 0, isMiss: false, hitType: 'blocked_sw',
            skillName: 'Safety Wall', timestamp: Date.now()
        });
        return true;
    }
    return false;
}

// Devotion CC break helper: called after applyStatusEffect returns devotionBroken=true
function handleDevotionCCBreak(result, zone) {
    if (!result || !result.devotionBroken || !result.brokenLinks) return;
    for (const link of result.brokenLinks) {
        const pt = connectedPlayers.get(link.targetCharId);
        if (pt) {
            pt.devotedTo = null;
            removeBuff(pt, 'devotion_protection');
            broadcastToZone(zone, 'skill:buff_removed', {
                targetId: link.targetCharId, isEnemy: false,
                buffName: 'devotion_protection', reason: 'crusader_cc'
            });
        }
    }
}

// Wrapper: apply status effect and handle Devotion CC break automatically
function applyStatusWithDevotionCheck(source, target, statusType, baseChance, overrideDuration, zone) {
    const result = applyStatusEffect(source, target, statusType, baseChance, overrideDuration);
    if (result && result.devotionBroken) {
        handleDevotionCCBreak(result, zone || target.zone || 'prontera_south');
    }
    return result;
}

function checkAutoBerserk(player, characterId, zone) {
    if (!player.activeBuffs) return;
    const abBuff = player.activeBuffs.find(b => b.name === 'auto_berserk' && Date.now() < b.expiresAt);
    if (!abBuff) return;

    const hpRatio = player.health / player.maxHealth;
    const shouldBeActive = hpRatio < 0.25 && player.health > 0;
    const currentlyActive = (abBuff.atkIncrease || 0) > 0;

    if (shouldBeActive && !currentlyActive) {
        // Activate ATK bonus
        abBuff.atkIncrease = abBuff.conditionalAtkIncrease || 32;
        const bZone = zone || player.zone || 'prontera_south';
        broadcastToZone(bZone, 'skill:buff_applied', {
            targetId: characterId, targetName: player.characterName, isEnemy: false,
            casterId: characterId, casterName: player.characterName,
            skillId: 108, buffName: 'Auto Berserk', duration: abBuff.expiresAt - Date.now(),
            effects: { atkIncrease: abBuff.atkIncrease, activated: true }
        });
        // Send updated stats so CombatStatsWidget reflects +ATK/-DEF
        const sock = io.sockets.sockets.get(player.socketId);
        if (sock) {
            const effStats = getEffectiveStats(player);
            const derived = roDerivedStats(effStats);
            const finalAspd = Math.min(COMBAT.ASPD_CAP, derived.aspd + (player.weaponAspdMod || 0));
            sock.emit('player:stats', buildFullStatsPayload(characterId, player, effStats, derived, finalAspd));
        }
    } else if (!shouldBeActive && currentlyActive) {
        // Deactivate ATK bonus (buff stays, just no ATK increase)
        abBuff.atkIncrease = 0;
        const bZone = zone || player.zone || 'prontera_south';
        broadcastToZone(bZone, 'skill:buff_applied', {
            targetId: characterId, targetName: player.characterName, isEnemy: false,
            casterId: characterId, casterName: player.characterName,
            skillId: 108, buffName: 'Auto Berserk', duration: abBuff.expiresAt - Date.now(),
            effects: { atkIncrease: 0, activated: false }
        });
        // Send updated stats so CombatStatsWidget reflects restored ATK/DEF
        const sock = io.sockets.sockets.get(player.socketId);
        if (sock) {
            const effStats = getEffectiveStats(player);
            const derived = roDerivedStats(effStats);
            const finalAspd = Math.min(COMBAT.ASPD_CAP, derived.aspd + (player.weaponAspdMod || 0));
            sock.emit('player:stats', buildFullStatsPayload(characterId, player, effStats, derived, finalAspd));
        }
    }
}

// RO Classic: Taking >25% MaxHP in a single hit cancels active performance (Bug #18)
// Also cancels ensemble if either performer takes heavy damage.
function checkPerformanceDamageCancel(player, characterId, damage) {
    if (isPerforming(player) && damage > player.maxHealth * 0.25) {
        cancelPerformance(characterId, player, 'heavy_damage');
        logger.info(`[PERFORMANCE] ${player.characterName} performance cancelled by heavy damage (${damage} > 25% of ${player.maxHealth})`);
    }
    if (player.ensembleState && damage > player.maxHealth * 0.25) {
        endEnsemble(player.ensembleState.id, player.ensembleState, 'heavy_damage');
        logger.info(`[ENSEMBLE] ${player.characterName} ensemble cancelled by heavy damage (${damage} > 25% of ${player.maxHealth})`);
    }
}

// Get combined stat modifiers from both status effects AND buffs
// This replaces the old getBuffStatModifiers() — merges status + buff mods
function getCombinedModifiers(target) {
    const statusMods = getStatusModifiers(target);
    const buffMods = getBuffModifiers(target);
    return {
        // Merge multipliers (multiplicative)
        defMultiplier: statusMods.defMultiplier * buffMods.defMultiplier,
        softDefMultiplier: buffMods.softDefMultiplier || 1.0,  // Provoke/Auto Berserk reduce VIT soft DEF
        atkMultiplier: statusMods.atkMultiplier * buffMods.atkMultiplier,
        mdefMultiplier: statusMods.mdefMultiplier || 1.0,
        hitMultiplier: statusMods.hitMultiplier || 1.0,
        fleeMultiplier: statusMods.fleeMultiplier || 1.0,
        moveSpeedMultiplier: statusMods.moveSpeedMultiplier || 1.0,
        aspdMultiplier: buffMods.aspdMultiplier || 1.0,
        // Additive bonuses (from buffs)
        bonusMDEF: buffMods.bonusMDEF || 0,
        strBonus: buffMods.strBonus || 0,
        agiBonus: buffMods.agiBonus || 0,
        vitBonus: buffMods.vitBonus || 0,
        intBonus: buffMods.intBonus || 0,
        dexBonus: buffMods.dexBonus || 0,
        lukBonus: buffMods.lukBonus || 0,
        defPercent: buffMods.defPercent || 0,
        moveSpeedBonus: buffMods.moveSpeedBonus || 0,
        bonusHit: buffMods.bonusHit || 0,
        bonusFlee: buffMods.bonusFlee || 0,
        bonusCritical: buffMods.bonusCritical || 0,
        bonusPerfectDodge: buffMods.bonusPerfectDodge || 0,
        // Performance (Bard/Dancer) buff fields (Phase 4)
        bragiCastReduction: buffMods.bragiCastReduction || 0,
        bragiAcdReduction: buffMods.bragiAcdReduction || 0,
        bonusMaxHpPercent: buffMods.bonusMaxHpPercent || 0,
        bonusMaxSpPercent: buffMods.bonusMaxSpPercent || 0,
        spCostReduction: buffMods.spCostReduction || 0,
        // Ensemble flat bonuses (Phase 4B — Drum/Nibelungen/Siegfried/Mr. Kim)
        bonusATK: buffMods.bonusATK || 0,
        bonusDEF: buffMods.bonusDEF || 0,
        expBonusPct: buffMods.expBonusPct || 0,
        elementResist: buffMods.elementResist || null,
        statusResist: buffMods.statusResist || 0,
        noGemStone: buffMods.noGemStone || false,
        // ASPD Potion buff (FIX C2)
        aspdPotionReduction: buffMods.aspdPotionReduction || 0,
        // Overrides
        lukOverride: statusMods.lukOverride,
        overrideElement: statusMods.overrideElement,
        weaponElement: buffMods.weaponElement || null,
        // Prevention flags (from status effects)
        preventsMovement: statusMods.preventsMovement || false,
        preventsCasting: statusMods.preventsCasting || false,
        preventsAttack: statusMods.preventsAttack || false,
        preventsItems: statusMods.preventsItems || false,
        blocksHPRegen: statusMods.blocksHPRegen || false,
        blocksSPRegen: statusMods.blocksSPRegen || false,
        // Special buff flags
        isHidden: buffMods.isHidden || false,
        isPlayDead: buffMods.isPlayDead || false,
        doubleNextDamage: buffMods.doubleNextDamage || false,
        blockRanged: buffMods.blockRanged || false,
        energyCoatActive: buffMods.energyCoatActive || false,
        // Blacksmith buff flags (Phase 5A)
        noSizePenalty: buffMods.noSizePenalty || false,
        maximizePower: buffMods.maximizePower || false,
        // Rogue buff flags (Phase 5B)
        closeConfineActive: buffMods.closeConfineActive || false,
        hardDefReduction: buffMods.hardDefReduction || 0,
        vitMultiplier: buffMods.vitMultiplier || 1.0,
        intMultiplier: buffMods.intMultiplier || 1.0,
        // Crusader buff flags (Phase 2A)
        autoGuardChance: buffMods.autoGuardChance || 0,
        autoGuardMoveDelay: buffMods.autoGuardMoveDelay || 0,
        reflectShieldPercent: buffMods.reflectShieldPercent || 0,
        defenderRangedReduction: buffMods.defenderRangedReduction || 0,
        shrinkActive: buffMods.shrinkActive || false,
        devotedTo: buffMods.devotedTo || null,
        demonResist: buffMods.demonResist || 0,
        holyResist: buffMods.holyResist || 0,
        // Monk buff flags (Phase 3A)
        disableSPRegen: buffMods.disableSPRegen || false,
        furyActive: buffMods.furyActive || false,
        blockActiveSkills: buffMods.blockActiveSkills || false,
        overrideHardDEF: buffMods.overrideHardDEF || null,
        overrideHardMDEF: buffMods.overrideHardMDEF || null,
        // Sitting + Blade Stop (Monk Phase final)
        isSitting: buffMods.isSitting || false,
        bladeStopCatching: buffMods.bladeStopCatching || false,
        rootLockActive: buffMods.rootLockActive || false,
        rootLockEnemyId: buffMods.rootLockEnemyId || null,
        rootLockPlayerId: buffMods.rootLockPlayerId || null,
        rootLockBladeStopLevel: buffMods.rootLockBladeStopLevel || 0,
        // Individual status flags (backward compat)
        isFrozen: statusMods.isFrozen || false,
        isStoned: statusMods.isStoned || false,
        isPetrifying: statusMods.isPetrifying || false,
        isStunned: statusMods.isStunned || false,
        isSleeping: statusMods.isSleeping || false,
        isPoisoned: statusMods.isPoisoned || false,
        isBleeding: statusMods.isBleeding || false,
        isCursed: statusMods.isCursed || false,
        isBlind: statusMods.isBlind || false,
        isSilenced: statusMods.isSilenced || false,
        isConfused: statusMods.isConfused || false
    };
}

// Backward-compatible alias — old code calls getBuffStatModifiers, new code uses getCombinedModifiers
function getBuffStatModifiers(target) {
    return getCombinedModifiers(target);
}

// Calculate skill damage using full RO damage system
function calculateSkillDamage(attackerStats, targetStats, targetHardDef, skillMultiplier, attackerBuffMods, targetBuffMods, targetInfo = {}, attackerInfo = {}, skillOptions = {}) {
    return calculatePhysicalDamage(
        attackerStats, targetStats, targetHardDef,
        { ...targetInfo, buffMods: targetBuffMods || { defMultiplier: 1.0 } },
        { ...attackerInfo, buffMods: attackerBuffMods || { atkMultiplier: 1.0 } },
        { isSkill: true, skillMultiplier, ...skillOptions }
    );
}

// Calculate magic skill damage using the RO pre-renewal MATK system
function calculateMagicSkillDamage(attackerStats, targetStats, targetHardMdef, skillMultiplier, skillElement, targetInfo = {}) {
    const targetBuffMods = targetInfo.buffMods || { defMultiplier: 1.0, mdefMultiplier: 1.0, bonusMDEF: 0 };
    return roMagicalDamage(
        { stats: attackerStats, weaponMATK: 0, buffMods: { atkMultiplier: 1.0 } },
        { stats: targetStats, hardMdef: targetHardMdef,
          element: targetInfo.element || { type: 'neutral', level: 1 },
          buffMods: { ...targetBuffMods, mdefMultiplier: targetBuffMods.mdefMultiplier || 1.0 } },
        { skillMultiplier, skillElement }
    );
}

// Check if a player target has Magic Rod active and absorb the spell
// Returns true if absorbed (caller should skip damage), false otherwise
function checkMagicRodAbsorption(target, targetId, spellSpCost, zone) {
    if (!target || !target.activeBuffs) return false;
    const mrBuff = target.activeBuffs.find(b => b.name === 'magic_rod' && Date.now() < b.expiresAt);
    if (!mrBuff) return false;
    // Absorb: nullify damage, restore SP
    const absorbPct = mrBuff.absorbPct || 0;
    const spGained = Math.floor((spellSpCost || 0) * absorbPct / 100);
    target.mana = Math.min(target.maxMana || target.mana, target.mana + spGained);
    // Broadcast absorption event
    broadcastToZone(zone, 'skill:magic_rod_absorb', {
        targetId, targetName: target.characterName,
        spGained, absorbPct, buffName: 'Magic Rod'
    });
    // Emit health update to the absorber
    const targetSocket = io.sockets.sockets.get(target.socketId);
    if (targetSocket) {
        targetSocket.emit('combat:health_update', { characterId: targetId, health: target.health, maxHealth: target.maxHealth, mana: target.mana, maxMana: target.maxMana });
    }
    return true;
}

// RO Classic Heal formula: floor((baseLv + INT) / 8) * (4 + skillLevel * 8) * (100 + healPower) / 100
function calculateHealAmount(caster, skillLevel) {
    const stats = getEffectiveStats(caster);
    const baseLv = stats.level || 1;
    const intStat = stats.int || 1;
    let heal = Math.floor((baseLv + intStat) / 8) * (4 + skillLevel * 8);
    // Apply equipment + card healing power bonus (bHealPower, e.g., +20 = 20% more healing)
    const healPower = (caster.equipHealPower || 0) + (caster.cardHealPower || 0);
    if (healPower !== 0) {
        heal = Math.floor(heal * (100 + healPower) / 100);
    }
    return heal;
}

// Helper: execute a physical skill on an enemy target (shared by Envenom, Sand Attack, Arrow Repel, Mammonite, etc.)
// Returns { result, enemy, attackerPos, targetPos, zone } or null if failed (error emitted)
async function executePhysicalSkillOnEnemy(player, characterId, socket, skill, skillId, learnedLevel, levelData, effectVal, spCost, targetId, options = {}) {
    const enemy = enemies.get(targetId);
    if (!enemy || enemy.isDead) { socket.emit('skill:error', { message: 'Target not found' }); return null; }

    const attackerPos = await getPlayerPosition(characterId);
    if (!attackerPos) return null;
    const targetPos = { x: enemy.x, y: enemy.y, z: enemy.z };

    const dx = attackerPos.x - targetPos.x;
    const dy = attackerPos.y - targetPos.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const skillRange = (options.range || skill.range || player.attackRange || COMBAT.MELEE_RANGE) + (getEffectiveStats(player).bonusRange || 0);
    if (dist > skillRange + COMBAT.RANGE_TOLERANCE) {
        socket.emit('combat:out_of_range', { targetId, isEnemy: true, targetX: targetPos.x, targetY: targetPos.y, targetZ: targetPos.z, distance: dist, requiredRange: skillRange });
        return null;
    }

    // Pneuma check: ranged physical skills are blocked by Pneuma ground effect
    if (options.isRanged) {
        const targetPneumas = getGroundEffectsAtPosition(targetPos.x, targetPos.y, targetPos.z || 0, 100);
        if (targetPneumas.find(e => e.type === 'pneuma')) {
            player.mana = Math.max(0, player.mana - spCost);
            applySkillDelays(characterId, player, skillId, levelData, socket);
            const pnZone = player.zone || 'prontera_south';
            broadcastToZone(pnZone, 'skill:effect_damage', {
                attackerId: characterId, attackerName: player.characterName,
                targetId, targetName: enemy.name, isEnemy: true,
                skillId, skillName: skill.displayName, skillLevel: learnedLevel, element: 'neutral',
                damage: 0, isCritical: false, isMiss: true, hitType: 'pneuma',
                targetHealth: enemy.health, targetMaxHealth: enemy.maxHealth,
                attackerX: attackerPos.x, attackerY: attackerPos.y, attackerZ: attackerPos.z,
                targetX: targetPos.x, targetY: targetPos.y, targetZ: targetPos.z,
                timestamp: Date.now()
            });
            broadcastToZone(pnZone, 'enemy:health_update', { enemyId: targetId, health: enemy.health, maxHealth: enemy.maxHealth });
            socket.emit('skill:used', { skillId, skillName: skill.displayName, level: learnedLevel, spCost, remainingMana: player.mana, maxMana: player.maxMana });
            socket.emit('combat:health_update', { characterId, health: player.health, maxHealth: player.maxHealth, mana: player.mana, maxMana: player.maxMana });
            return null;
        }
    }

    player.mana = Math.max(0, player.mana - spCost);
    // System H: Consume catalysts/gems on skill execution
    const catalysts = SKILL_CATALYSTS[skill.name];
    if (catalysts && !player.cardNoGemStone) {
        for (const cat of catalysts) {
            if (cat.minLevel && learnedLevel < cat.minLevel) continue;
            await pool.query(
                `UPDATE character_inventory SET quantity = quantity - $3
                 WHERE ctid = (SELECT ctid FROM character_inventory WHERE character_id = $1 AND item_id = $2 AND is_equipped = false AND quantity >= $3 LIMIT 1)`,
                [characterId, cat.itemId, cat.quantity]
            );
        }
    }
    applySkillDelays(characterId, player, skillId, levelData, socket);

    const atkBuffMods = getBuffStatModifiers(player);
    const defBuffMods = getCombinedModifiers(enemy);
    const skillTargetInfo = getEnemyTargetInfo(enemy);
    skillTargetInfo.buffMods = defBuffMods;
    const skillAtkInfo = getAttackerInfo(player);
    skillAtkInfo.buffMods = atkBuffMods;

    const skillElement = options.forceElement || (skill.element === 'neutral' ? null : (skill.element || null));
    const result = calculateSkillDamage(
        getEffectiveStats(player), enemy.stats, enemy.hardDef || 0,
        effectVal, atkBuffMods, defBuffMods, skillTargetInfo, skillAtkInfo,
        { skillElement, forceHit: options.forceHit || false, skillId }
    );

    const zone = player.zone || 'prontera_south';
    if (!result.isMiss) {
        // Lex Aeterna: double damage on first hit, then consume
        if (result.damage > 0 && enemy.activeBuffs) {
            const lexBuff = enemy.activeBuffs.find(b => b.name === 'lex_aeterna' && Date.now() < b.expiresAt);
            if (lexBuff) {
                result.damage = result.damage * 2;
                removeBuff(enemy, 'lex_aeterna');
                broadcastToZone(zone, 'skill:buff_removed', { targetId, isEnemy: true, buffName: 'lex_aeterna', reason: 'consumed' });
            }
        }
        enemy.health = Math.max(0, enemy.health - result.damage);
        enemy.lastDamageTime = Date.now();
        if (typeof setEnemyAggro === 'function') setEnemyAggro(enemy, characterId, 'melee', result.damage);
        const broken = checkDamageBreakStatuses(enemy);
        for (const bt of broken) {
            broadcastToZone(zone, 'status:removed', { targetId, isEnemy: true, statusType: bt, reason: 'damage_break' });
            broadcastToZone(zone, 'skill:buff_removed', { targetId, isEnemy: true, buffName: bt, reason: 'damage_break' });
        }
        // Raid debuff hit counter: decrement on skill damage (pre-renewal: all damage counts)
        decrementRaidDebuffHits(enemy, zone);
    }

    broadcastToZone(zone, 'skill:effect_damage', {
        attackerId: characterId, attackerName: player.characterName,
        targetId, targetName: enemy.name, isEnemy: true,
        skillId, skillName: skill.displayName, skillLevel: learnedLevel, element: result.element || 'neutral',
        damage: result.isMiss ? 0 : result.damage, isCritical: result.isCritical, isMiss: result.isMiss, hitType: result.hitType,
        targetHealth: enemy.health, targetMaxHealth: enemy.maxHealth,
        attackerX: attackerPos.x, attackerY: attackerPos.y, attackerZ: attackerPos.z,
        targetX: targetPos.x, targetY: targetPos.y, targetZ: targetPos.z,
        timestamp: Date.now()
    });
    broadcastToZone(zone, 'enemy:health_update', { enemyId: targetId, health: enemy.health, maxHealth: enemy.maxHealth, inCombat: true });

    if (enemy.health <= 0) {
        await processEnemyDeathFromSkill(enemy, player, characterId, io);
    }

    socket.emit('skill:used', { skillId, skillName: skill.displayName, level: learnedLevel, spCost, remainingMana: player.mana, maxMana: player.maxMana });
    socket.emit('combat:health_update', { characterId, health: player.health, maxHealth: player.maxHealth, mana: player.mana, maxMana: player.maxMana });
    return { result, enemy, attackerPos, targetPos, zone };
}

// Helper: process enemy death from skill kill (shares logic with auto-attack kill)
// ============================================================
// Homunculus behavior on owner death (Phase G1):
// HP >= 80%: auto-vaporize (save state to DB, removable from activeHomunculi)
// HP < 80%: homunculus stays alive but owner is dead — stops receiving commands
// In RO Classic, homunculus dies if owner dies without enough HP to vaporize,
// but we use the gentler auto-vaporize approach for better UX.
function handleHomunculusOnOwnerDeath(characterId, player, zone) {
    const hState = activeHomunculi.get(characterId);
    if (!hState || !hState.isAlive || !hState.isSummoned) return;

    if (hState.hpCurrent >= Math.floor(hState.hpMax * 0.8)) {
        // HP >= 80%: auto-vaporize (save state, can be re-summoned)
        hState.isSummoned = false;
        activeHomunculi.delete(characterId);

        // Persist state to DB
        pool.query(
            `UPDATE character_homunculus SET is_summoned = false, hp_current = $2, sp_current = $3,
             experience = $4, intimacy = $5, hunger = $6, level = $7,
             hp_max = $8, sp_max = $9, str = $10, agi = $11, vit = $12, int_stat = $13, dex = $14, luk = $15,
             skill_1_level = $16, skill_2_level = $17, skill_3_level = $18, skill_points = $19,
             updated_at = NOW()
             WHERE character_id = $1`,
            [characterId, hState.hpCurrent, hState.spCurrent, hState.experience, hState.intimacy, hState.hunger,
             hState.level, hState.hpMax, hState.spMax, hState.str, hState.agi, hState.vit, hState.int_stat, hState.dex, hState.luk,
             hState.skill1Level, hState.skill2Level, hState.skill3Level, hState.skillPoints]
        ).catch(err => logger.error(`[HOMUNCULUS] Failed to persist auto-vaporize on owner death:`, err.message));

        const sock = io.sockets.sockets.get(player.socketId);
        if (sock) sock.emit('homunculus:vaporized', { reason: 'owner_death' });
        broadcastToZone(zone, 'homunculus:other_dismissed', { ownerId: characterId });
        logger.info(`[HOMUNCULUS] ${hState.name} auto-vaporized on owner ${player.characterName} death (HP ${hState.hpCurrent}/${hState.hpMax} >= 80%)`);
    } else {
        // HP < 80%: homunculus stays alive but stops receiving commands
        hState.command = 'standby';
        hState.targetId = null;
        logger.info(`[HOMUNCULUS] ${hState.name} entered standby on owner ${player.characterName} death (HP ${hState.hpCurrent}/${hState.hpMax} < 80%)`);
    }
}

// Blacksmith Audit Fix: Clear buffs on player death (rAthena: status_change_clear on pc_dead)
// Buffs with NoRemoveOnDead in rAthena pre-re/status.yml survive death.
// ============================================================
const BUFFS_SURVIVE_DEATH = new Set([
    'auto_berserk', 'endure', 'shrink',
    'song_whistle', 'song_assassin_cross', 'song_bragi', 'song_apple_of_idun',
    'song_humming', 'dance_fortune_kiss', 'dance_service_for_you', 'dance_pdfm'
]);

function clearBuffsOnDeath(player, characterId, zone) {
    // Cancel active trade on death
    if (player.isTrading) { cancelTrade(characterId, 'Player died.'); }
    if (!player.activeBuffs || player.activeBuffs.length === 0) return;
    const removed = [];
    player.activeBuffs = player.activeBuffs.filter(b => {
        if (BUFFS_SURVIVE_DEATH.has(b.name)) return true;
        removed.push(b.name);
        return false;
    });
    // Clear Blacksmith toggle states
    player.maximizePowerActive = false;
    player.weaponBroken = false;
    // Clear Bard/Dancer performance state
    if (player.performanceState) {
        cancelPerformance(characterId, player, 'death');
    }
    // Clear Bard/Dancer ensemble state
    if (player.ensembleState) {
        endEnsemble(player.ensembleState.id, player.ensembleState, 'death');
    }
    // Broadcast removals
    for (const name of removed) {
        broadcastToZone(zone, 'skill:buff_removed', {
            targetId: characterId, isEnemy: false, buffName: name, reason: 'death'
        });
    }
    if (removed.length > 0) {
        logger.info(`[DEATH] Cleared ${removed.length} buffs on death for ${player.characterName}: ${removed.join(', ')}`);
    }
}

// RO Classic pre-renewal death penalty (rAthena pc_dead(), exp.conf verified):
// - Lose 1% of base EXP needed for current level (death_penalty_base: 100)
// - Lose 1% of job EXP needed for current job level (death_penalty_job: 100)
// - Novice class: EXEMPT (zero penalty) — rAthena: (sd->class_&MAPID_SECONDMASK) != MAPID_NOVICE
// - Max level: no penalty (nextLevelExp returns 0)
// - Cannot delevel (EXP clamped at 0 within current level)
// - PvP/WoE maps: no penalty (handled by caller — only called from PvE paths)
// - Penalty applies regardless of damage source (monster, DoT, self-kill)
function applyDeathPenalty(player, characterId, socket) {
    // Novice class exempt from death penalty (rAthena: MAPID_NOVICE check)
    const jobClass = (player.jobClass || 'novice').toLowerCase();
    if (jobClass === 'novice') return;

    const baseLevel = (player.stats && player.stats.level) || 1;
    const jobLevel = player.jobLevel || 1;

    // Base EXP penalty: 1% of EXP needed for current base level
    const baseExpForLevel = getBaseExpForNextLevel(baseLevel);
    if (baseExpForLevel > 0) {
        const basePenalty = Math.floor(baseExpForLevel * 0.01);
        if (basePenalty > 0 && (player.baseExp || 0) > 0) {
            player.baseExp = Math.max(0, (player.baseExp || 0) - basePenalty);
            logger.info(`[DEATH PENALTY] ${player.characterName} lost ${basePenalty} base EXP (1% of ${baseExpForLevel}). Remaining: ${player.baseExp}`);
        }
    }

    // Job EXP penalty: 1% of EXP needed for current job level
    const jobExpForLevel = getJobExpForNextLevel(jobClass, jobLevel);
    if (jobExpForLevel > 0) {
        const jobPenalty = Math.floor(jobExpForLevel * 0.01);
        if (jobPenalty > 0 && (player.jobExp || 0) > 0) {
            player.jobExp = Math.max(0, (player.jobExp || 0) - jobPenalty);
            logger.info(`[DEATH PENALTY] ${player.characterName} lost ${jobPenalty} job EXP (1% of ${jobExpForLevel}). Remaining: ${player.jobExp}`);
        }
    }

    // Save to DB (fire-and-forget, non-blocking)
    pool.query('UPDATE characters SET base_exp = $1, job_exp = $2 WHERE character_id = $3',
        [player.baseExp || 0, player.jobExp || 0, characterId])
        .catch(err => logger.warn(`[DEATH PENALTY] DB save failed for ${characterId}: ${err.message}`));
    // Notify client of updated EXP
    if (socket) {
        const effStats = getEffectiveStats(player);
        const derived = roDerivedStats(effStats);
        const finalAspd = Math.min(COMBAT.ASPD_CAP, derived.aspd + (player.weaponAspdMod || 0));
        socket.emit('player:stats', buildFullStatsPayload(characterId, player, effStats, derived, finalAspd));
    }

    // Pet intimacy loss on owner death: -20 (rAthena: IntimacyOwnerDie)
    const petState = activePets.get(characterId);
    if (petState) {
        const petData = getPetData(petState.mobId);
        petState.intimacy = Math.max(0, petState.intimacy + (petData ? petData.intimacyOwnerDie : -20));
        if (petState.intimacy <= 0) {
            // Pet runs away
            pool.query('DELETE FROM character_pets WHERE id = $1', [petState.petId]).catch(() => {});
            activePets.delete(characterId);
            player.petBonuses = {};
            if (socket) {
                socket.emit('pet:ran_away', { petId: petState.petId, petName: petState.name });
                socket.emit('chat:receive', { type: 'chat:receive', channel: 'SYSTEM', senderId: 0, senderName: 'SYSTEM', message: `${petState.name} has run away!`, timestamp: Date.now() });
            }
            logger.info(`[PET] ${player.characterName}'s ${petState.name} RAN AWAY (owner death, intimacy 0)`);
        } else {
            pool.query('UPDATE character_pets SET intimacy = $1 WHERE id = $2', [petState.intimacy, petState.petId]).catch(() => {});
            if (socket) socket.emit('pet:hunger_update', { hunger: petState.hunger, intimacy: petState.intimacy, hungerLevel: getHungerLevel(petState.hunger), intimacyLevel: getIntimacyLevel(petState.intimacy) });
        }
    }
}

async function processEnemyDeathFromSkill(enemy, attacker, attackerId, io) {
    enemy.isDead = true;
    enemy.aiState = AI_STATE.DEAD;
    enemy.targetPlayerId = null;
    // Clean up root_lock on enemy death — free the locked player
    if (hasBuff(enemy, 'root_lock')) {
        const rlBuff = enemy.activeBuffs.find(b => b.name === 'root_lock');
        if (rlBuff && rlBuff.lockedPlayerId) {
            const lockedPlayer = connectedPlayers.get(rlBuff.lockedPlayerId);
            if (lockedPlayer) {
                removeBuff(lockedPlayer, 'root_lock');
                const rlZone = lockedPlayer.zone || 'prontera_south';
                broadcastToZone(rlZone, 'skill:buff_removed', { targetId: rlBuff.lockedPlayerId, isEnemy: false, buffName: 'root_lock', reason: 'enemy_death' });
            }
        }
        removeBuff(enemy, 'root_lock');
    }
    // Close Confine: remove paired buff on death
    if (enemy.activeBuffs && enemy.activeBuffs.some(b => b.name === 'close_confine')) {
        breakCloseConfine(enemy, enemy.zone || 'prontera_south', io, 'death');
    }
    // Slave death: decrement master's slave count and remove from master's _slaves Set
    if (enemy._isSlave && enemy._masterId) {
        const master = enemies.get(enemy._masterId);
        if (master) {
            if (master._slaves) master._slaves.delete(enemy.enemyId);
            master._slaveCount = master._slaves ? master._slaves.size : 0;
            logger.info(`[SLAVE] Slave ${enemy.name}(${enemy.enemyId}) died, master ${master.name}(${master.enemyId}) now has ${master._slaveCount} slaves`);
        }
        // RO Classic: Slaves give NO EXP and NO drops. Only broadcast death + cleanup.
        const slaveZone = enemy.zone || 'prontera_south';
        for (const [otherId, otherAtk] of autoAttackState.entries()) {
            if (otherAtk.isEnemy && otherAtk.targetCharId === enemy.enemyId) autoAttackState.delete(otherId);
        }
        broadcastToZone(slaveZone, 'enemy:death', {
            enemyId: enemy.enemyId, enemyName: enemy.name,
            killerId: attacker ? (attacker.characterId || attackerId) : 0, killerName: attacker ? attacker.characterName : '',
            isEnemy: true, isDead: true, timestamp: Date.now()
        });
        enemies.delete(enemy.enemyId);
        return; // Skip EXP, drops, and everything else
    }

    logger.info(`[SKILL-COMBAT] Enemy ${enemy.name}(${enemy.enemyId}) killed by ${attacker.characterName} (skill)`);

    // Stop all auto-attackers targeting this enemy
    // Capture attacker count AND combat data BEFORE clearing (for EXP tap bonus + MVP)
    const attackerCount = enemy.inCombatWith ? enemy.inCombatWith.size : 1;
    const mvpCombatData = new Map(enemy.inCombatWith); // Snapshot for MVP determination
    for (const [otherId, otherAtk] of autoAttackState.entries()) {
        if (otherAtk.isEnemy && otherAtk.targetCharId === enemy.enemyId) {
            autoAttackState.delete(otherId);
        }
    }
    enemy.inCombatWith.clear();

    // Card kill hooks (Phase 2): SP/HP gain on kill, Zeny, EXP bonus
    const cardKillResult = processCardKillHooks(attacker, enemy, attackerId, io);

    // Card drop bonuses (Phase 8): extra item drops from cards
    const cardExtraDrops = processCardDropBonuses(attacker, enemy);

    // Award EXP (with card race bonus + party distribution)
    let baseExpReward = enemy.baseExp || 0;
    let jobExpReward = enemy.jobExp || 0;
    if (cardKillResult.expBonusPercent > 0) {
        baseExpReward = Math.floor(baseExpReward * (100 + cardKillResult.expBonusPercent) / 100);
        jobExpReward = Math.floor(jobExpReward * (100 + cardKillResult.expBonusPercent) / 100);
    }

    // Ensemble EXP bonus (Mr. Kim A Rich Man)
    const killBuffMods = getCombinedModifiers(attacker);
    const ensembleExpBonus = killBuffMods.expBonusPct || 0;
    if (ensembleExpBonus > 0) {
        baseExpReward = Math.floor(baseExpReward * (100 + ensembleExpBonus) / 100);
        jobExpReward = Math.floor(jobExpReward * (100 + ensembleExpBonus) / 100);
    }

    // EXP Tap Bonus: +25% per additional attacker (rAthena pre-renewal)
    if (attackerCount > 1) {
        const tapBonus = 100 + 25 * Math.min(11, attackerCount - 1);
        baseExpReward = Math.floor(baseExpReward * tapBonus / 100);
        jobExpReward = Math.floor(jobExpReward * tapBonus / 100);
    }

    // Party EXP distribution
    const enemyZoneForExp = enemy.zone || 'prontera_south';
    const expRecipients = distributePartyEXP(attacker, attackerId, baseExpReward, jobExpReward, enemyZoneForExp);

    for (const recipient of expRecipients) {
        const expResult = processExpGain(recipient.player, recipient.baseExp, recipient.jobExp);
        const rSocket = io.sockets.sockets.get(recipient.player.socketId);

        if (rSocket && (expResult.baseExpGained > 0 || expResult.jobExpGained > 0)) {
            rSocket.emit('exp:gain', {
                characterId: recipient.charId,
                baseExpGained: expResult.baseExpGained,
                jobExpGained: expResult.jobExpGained,
                enemyName: enemy.name,
                enemyLevel: enemy.level,
                exp: buildExpPayload(recipient.player),
                baseLevelUps: expResult.baseLevelUps,
                jobLevelUps: expResult.jobLevelUps,
                partyShared: recipient.partyShared || false,
                originalBaseExp: recipient.originalBaseExp || 0,
                originalJobExp: recipient.originalJobExp || 0,
                partyBonusPct: recipient.partyBonusPct || 0,
                memberCount: recipient.memberCount || 1
            });

            if (expResult.baseLevelUps.length > 0 || expResult.jobLevelUps.length > 0) {
                const levelUpPayload = {
                    characterId: recipient.charId, characterName: recipient.player.characterName,
                    baseLevelUps: expResult.baseLevelUps, jobLevelUps: expResult.jobLevelUps,
                    totalStatPoints: expResult.totalStatPoints, totalSkillPoints: expResult.totalSkillPoints,
                    exp: buildExpPayload(recipient.player)
                };
                rSocket.emit('exp:level_up', levelUpPayload);
                const recipientZone = recipient.player.zone || 'prontera_south';
                broadcastToZoneExcept(rSocket, recipientZone, 'exp:level_up', levelUpPayload);

                const effectiveStats = getEffectiveStats(recipient.player);
                const newDerived = calculateDerivedStats(effectiveStats);
                const newFinalAspd = Math.min(COMBAT.ASPD_CAP, newDerived.aspd + (recipient.player.weaponAspdMod || 0));
                rSocket.emit('player:stats', buildFullStatsPayload(recipient.charId, recipient.player, effectiveStats, newDerived, newFinalAspd));
                broadcastToZone(recipientZone, 'combat:health_update', {
                    characterId: recipient.charId, health: recipient.player.health,
                    maxHealth: recipient.player.maxHealth, mana: recipient.player.mana, maxMana: recipient.player.maxMana
                });
                for (const lu of expResult.baseLevelUps) {
                    io.emit('chat:receive', { type: 'chat:receive', channel: 'SYSTEM', senderId: 0, senderName: 'SYSTEM',
                        message: `${recipient.player.characterName} has reached Base Level ${lu.newLevel}!`, timestamp: Date.now() });
                }
                for (const lu of expResult.jobLevelUps) {
                    io.emit('chat:receive', { type: 'chat:receive', channel: 'SYSTEM', senderId: 0, senderName: 'SYSTEM',
                        message: `${recipient.player.characterName} has reached Job Level ${lu.newJobLevel}!`, timestamp: Date.now() });
                }
            }
            saveExpDataToDB(recipient.charId, recipient.player);
        }
        // Update party member level if changed
        if (recipient.player.partyId && expResult.baseLevelUps.length > 0) {
            const prt = activeParties.get(recipient.player.partyId);
            if (prt) {
                const mem = prt.members.get(recipient.charId);
                if (mem) mem.level = recipient.player.stats?.level || recipient.player.level || 1;
            }
        }
    }

    const killerSocket = io.sockets.sockets.get(attacker.socketId);

    // ── MVP Reward System (RO Classic pre-renewal) ──
    // Highest total damage dealer wins MVP title, bonus EXP, and 3 MVP drop rolls
    if (enemy.monsterClass === 'mvp' && mvpCombatData && mvpCombatData.size > 0) {
        // Find MVP winner (highest damage) — uses snapshot taken before clear()
        let mvpCharId = attackerId; // fallback to killer
        let mvpDamage = 0;
        for (const [cId, data] of mvpCombatData.entries()) {
            if (data.totalDamage > mvpDamage) {
                mvpDamage = data.totalDamage;
                mvpCharId = cId;
            }
        }
        const mvpPlayer = connectedPlayers.get(mvpCharId);
        const mvpSocket = mvpPlayer ? io.sockets.sockets.get(mvpPlayer.socketId) : null;

        // Award MVP bonus EXP
        const mvpExpReward = enemy.mvpExp || 0;
        if (mvpPlayer && mvpExpReward > 0) {
            const mvpExpResult = processExpGain(mvpPlayer, mvpExpReward, 0);
            if (mvpSocket) {
                mvpSocket.emit('exp:gain', {
                    characterId: mvpCharId,
                    baseExpGained: mvpExpResult.baseExpGained,
                    jobExpGained: 0,
                    enemyName: enemy.name + ' (MVP Bonus)',
                    enemyLevel: enemy.level,
                    exp: buildExpPayload(mvpPlayer),
                    baseLevelUps: mvpExpResult.baseLevelUps,
                    jobLevelUps: []
                });
            }
            saveExpDataToDB(mvpCharId, mvpPlayer);
            logger.info(`[MVP] ${mvpPlayer.characterName} won MVP for ${enemy.name}! Bonus EXP: ${mvpExpReward}, Total damage: ${mvpDamage}`);
        }

        // Roll 3 MVP drops for the winner
        if (mvpPlayer && enemy.mvpDrops && enemy.mvpDrops.length > 0) {
            for (const mvpDrop of enemy.mvpDrops) {
                const roll = Math.random() * 10000;
                if (roll < (mvpDrop.chance || 0)) {
                    const mvpItemDef = itemDefinitions.get(mvpDrop.itemId);
                    const added = await addItemToInventory(mvpCharId, mvpDrop.itemId, 1);
                    if (added && mvpSocket) {
                        mvpSocket.emit('loot:drop', {
                            items: [{ itemId: mvpDrop.itemId, itemName: mvpItemDef ? mvpItemDef.name : `Item ${mvpDrop.itemId}`,
                                quantity: 1, icon: mvpItemDef ? mvpItemDef.icon : 'default_item',
                                itemType: mvpItemDef ? mvpItemDef.item_type : 'etc' }]
                        });
                    }
                    logger.info(`[MVP DROP] ${mvpPlayer.characterName} received ${mvpItemDef ? mvpItemDef.name : mvpDrop.itemId} from ${enemy.name} MVP`);
                }
            }
        }

        // Server-wide MVP announcement
        const mvpName = mvpPlayer ? mvpPlayer.characterName : 'Unknown';
        io.emit('chat:receive', {
            type: 'chat:receive', channel: 'SYSTEM', senderId: 0, senderName: 'SYSTEM',
            message: `[MVP] ${mvpName} has defeated ${enemy.name}!`,
            timestamp: Date.now()
        });

        // Emit MVP tombstone data for client display
        const enemyZoneForMvp = enemy.zone || 'prontera_south';
        broadcastToZone(enemyZoneForMvp, 'mvp:tombstone', {
            enemyId: enemy.enemyId, bossName: enemy.name,
            killerName: mvpName, x: enemy.x, y: enemy.y, z: enemy.z || 300,
            timestamp: Date.now()
        });
    }

    // Despawn slave monsters when master dies (no EXP/drops for master-death kills)
    if (enemy._slaves && enemy._slaves.size > 0) {
        const slaveZone = enemy.zone || 'prontera_south';
        for (const slaveId of enemy._slaves) {
            const slave = enemies.get(slaveId);
            if (slave && !slave.isDead) {
                slave.isDead = true;
                slave.aiState = AI_STATE.DEAD;
                slave.health = 0;
                // Stop anyone auto-attacking this slave
                for (const [sOtherId, sOtherAtk] of autoAttackState.entries()) {
                    if (sOtherAtk.isEnemy && sOtherAtk.targetCharId === slaveId) {
                        autoAttackState.delete(sOtherId);
                    }
                }
                broadcastToZone(slaveZone, 'enemy:death', {
                    enemyId: slaveId, enemyName: slave.name, killerId: 0, killerName: 'master_death',
                    isEnemy: true, isDead: true, timestamp: Date.now()
                });
                enemies.delete(slaveId);
                logger.info(`[SLAVE] Slave ${slave.name}(${slaveId}) killed by master death`);
            }
        }
        enemy._slaves.clear();
        enemy._slaveCount = 0;
    }

    // Broadcast enemy death to zone
    const enemyZone = enemy.zone || 'prontera_south';
    broadcastToZone(enemyZone, 'enemy:death', {
        enemyId: enemy.enemyId, enemyName: enemy.name,
        killerId: attackerId, killerName: attacker.characterName,
        isEnemy: true, isDead: true,
        baseExp: baseExpReward, jobExp: jobExpReward, exp: enemy.exp,
        timestamp: Date.now()
    });

    // Roll and award loot (including Phase 8 card bonus drops)
    const droppedItems = rollEnemyDrops(enemy);
    if (cardExtraDrops.length > 0) {
        for (const cd of cardExtraDrops) {
            droppedItems.push(cd);
        }
    }
    if (droppedItems.length > 0) {
        const lootItems = [];
        let addedToDb = false;
        const lootPlayer = connectedPlayers.get(attackerId);
        for (const drop of droppedItems) {
            if (drop.itemId) {
                // RO Classic: skip pickup if player would exceed max weight
                if (lootPlayer) {
                    const dropDef = itemDefinitions.get(drop.itemId);
                    const dropWeight = dropDef ? (dropDef.weight || 0) * drop.quantity : 0;
                    if ((lootPlayer.currentWeight || 0) + dropWeight > getPlayerMaxWeight(lootPlayer)) {
                        logger.info(`[WEIGHT] ${lootPlayer.characterName} overweight — skipped ${drop.quantity}x ${drop.itemName}`);
                        continue;
                    }
                }
                // RO Classic: equipment drops as unidentified (weapons, armor)
                const dropItemDef = itemDefinitions.get(drop.itemId);
                const dropIdentified = !dropItemDef || !['weapon', 'armor'].includes(dropItemDef.item_type);
                const added = await addItemToInventory(attackerId, drop.itemId, drop.quantity, null, dropIdentified);
                if (added) {
                    const itemDef = dropItemDef;
                    lootItems.push({ itemId: drop.itemId, itemName: drop.itemName, quantity: drop.quantity,
                        icon: itemDef ? itemDef.icon : 'default_item', itemType: itemDef ? itemDef.item_type : 'etc',
                        identified: dropIdentified });
                    addedToDb = true;
                    // Update cached weight so subsequent drops in same loop check correctly
                    if (lootPlayer) {
                        const dropDef = itemDefinitions.get(drop.itemId);
                        lootPlayer.currentWeight = (lootPlayer.currentWeight || 0) + (dropDef ? (dropDef.weight || 0) * drop.quantity : 0);
                    }
                }
            } else {
                lootItems.push({ itemId: null, itemName: drop.itemName, quantity: drop.quantity,
                    icon: 'default_item', itemType: 'etc' });
            }
        }
        if (lootItems.length > 0 && killerSocket) {
            killerSocket.emit('loot:drop', { enemyId: enemy.enemyId, enemyName: enemy.name, items: lootItems });
            if (addedToDb) {
                const killerInventory = await getPlayerInventory(attackerId);
                killerSocket.emit('inventory:data', { items: killerInventory, zuzucoin: attacker.zuzucoin, currentWeight: attacker.currentWeight || 0, maxWeight: getPlayerMaxWeight(attacker) });
                // Update weight cache from DB (authoritative) after loot
                if (lootPlayer) await updatePlayerWeightCache(attackerId, lootPlayer);
            }
        }
    }

    // Ore Discovery passive (Blacksmith) — extra ore drop on kill
    if (attacker && attacker.learnedSkills) {
        const oreDiscoveryLv = attacker.learnedSkills[1208] || (Array.isArray(attacker.learnedSkills) ? (attacker.learnedSkills.find(s => s.id === 1208) ? 1 : 0) : 0);
        if (oreDiscoveryLv > 0) {
            const IG_ORE = [
                { itemId: 1002, name: 'Iron Ore', rate: 1132 },
                { itemId: 998, name: 'Iron', rate: 1057 },
                { itemId: 993, name: 'Green Live', rate: 981 },
                { itemId: 1003, name: 'Coal', rate: 906 },
                { itemId: 992, name: 'Wind of Verdure', rate: 830 },
                { itemId: 1010, name: 'Phracon', rate: 755 },
                { itemId: 991, name: 'Crystal Blue', rate: 679 },
                { itemId: 990, name: 'Red Blood', rate: 604 },
                { itemId: 999, name: 'Steel', rate: 528 },
                { itemId: 1011, name: 'Emveretarcon', rate: 453 },
                { itemId: 757, name: 'Rough Elunium', rate: 377 },
                { itemId: 756, name: 'Rough Oridecon', rate: 340 },
                { itemId: 997, name: 'Great Nature', rate: 302 },
                { itemId: 996, name: 'Rough Wind', rate: 264 },
                { itemId: 995, name: 'Mystic Frozen', rate: 226 },
                { itemId: 994, name: 'Flame Heart', rate: 189 },
                { itemId: 985, name: 'Elunium', rate: 151 },
                { itemId: 984, name: 'Oridecon', rate: 113 },
                { itemId: 969, name: 'Gold', rate: 75 },
                { itemId: 714, name: 'Emperium', rate: 38 },
            ];
            // Pick random item from group (equal chance), then check that item's individual rate
            const picked = IG_ORE[Math.floor(Math.random() * IG_ORE.length)];
            if (Math.random() < (picked.rate * 2 + 1) / 20001) {
                // Weight check before adding ore
                const oreDef = itemDefinitions.get(picked.itemId);
                const oreWeight = oreDef ? (oreDef.weight || 0) : 0;
                if ((attacker.currentWeight || 0) + oreWeight <= getPlayerMaxWeight(attacker)) {
                    const oreAdded = await addItemToInventory(attackerId, picked.itemId, 1);
                    if (oreAdded && killerSocket) {
                        killerSocket.emit('chat:receive', JSON.stringify({
                            type: 'system', message: `Ore Discovery: Found ${picked.name}!`
                        }));
                        killerSocket.emit('loot:drop', { enemyId: enemy.enemyId, enemyName: enemy.name, items: [{ itemId: picked.itemId, itemName: picked.name, quantity: 1, icon: oreDef ? oreDef.icon : 'default_item', itemType: oreDef ? oreDef.item_type : 'etc' }] });
                        // Refresh inventory after ore drop
                        const oreInventory = await getPlayerInventory(attackerId);
                        killerSocket.emit('inventory:data', { items: oreInventory, zuzucoin: attacker.zuzucoin, currentWeight: attacker.currentWeight || 0, maxWeight: getPlayerMaxWeight(attacker) });
                        await updatePlayerWeightCache(attackerId, attacker);
                    }
                    logger.info(`[ORE_DISCOVERY] ${attacker.characterName} found ${picked.name} from ${enemy.name}`);
                }
            }
        }
    }

    // Homunculus EXP sharing: if owner has an active homunculus, give it 10% of base EXP
    const ownerHState = activeHomunculi.get(attackerId);
    if (ownerHState && ownerHState.isAlive && ownerHState.isSummoned && ownerHState.level < 99) {
        const hExpGain = Math.floor((enemy.baseExp || 0) * 0.1);
        if (hExpGain > 0) {
            ownerHState.experience += hExpGain;
            while (ownerHState.level < 99) {
                const expNeeded = getExpToNextLevel(ownerHState.level);
                if (expNeeded <= 0 || ownerHState.experience < expNeeded) break;
                ownerHState.experience -= expNeeded;
                ownerHState.level++;
                const gains = applyLevelUpGrowth(ownerHState);
                ownerHState.skillPoints += (ownerHState.level % 3 === 0) ? 1 : 0;
                const newStats = calculateHomunculusStats(ownerHState);
                if (killerSocket) {
                    killerSocket.emit('homunculus:leveled_up', {
                        level: ownerHState.level, gains,
                        hpMax: ownerHState.hpMax, spMax: ownerHState.spMax, skillPoints: ownerHState.skillPoints,
                        stats: { str: ownerHState.str, agi: ownerHState.agi, vit: ownerHState.vit, int: ownerHState.int_stat, dex: ownerHState.dex, luk: ownerHState.luk, ...newStats },
                        experience: ownerHState.experience, expToNext: getExpToNextLevel(ownerHState.level)
                    });
                }
                logger.info(`[HOMUNCULUS] ${ownerHState.name} leveled up to ${ownerHState.level} from owner kill!`);
            }
        }
    }

    // Schedule respawn — MVPs/bosses get random variance (RO Classic pre-renewal)
    // MVP: base 120min + 0-10min variance. Boss: base 60min + 0-10min variance. Normal: fixed.
    let respawnDelay = enemy.respawnMs || 15000;
    if (enemy.monsterClass === 'mvp') {
        respawnDelay = 7200000 + Math.floor(Math.random() * 600000); // 120-130 min
    } else if (enemy.monsterClass === 'boss') {
        respawnDelay = 3600000 + Math.floor(Math.random() * 600000); // 60-70 min
    }
    // Slaves don't respawn independently
    if (enemy._isSlave) {
        enemies.delete(enemy.enemyId);
        return;
    }
    setTimeout(() => {
        enemy.health = enemy.maxHealth;
        enemy.isDead = false;
        enemy.x = enemy.spawnX; enemy.y = enemy.spawnY; enemy.z = enemy.spawnZ;
        enemy.targetPlayerId = null;
        enemy.inCombatWith = new Map();
        enemy._slaves = null;
        enemy._slaveCount = 0;
        if (typeof initEnemyWanderState === 'function') initEnemyWanderState(enemy);
        const respawnPayload = {
            enemyId: enemy.enemyId, templateId: enemy.templateId, name: enemy.name,
            level: enemy.level, health: enemy.health, maxHealth: enemy.maxHealth,
            x: enemy.x, y: enemy.y, z: enemy.z
        };
        if (enemy.spriteClass) {
            respawnPayload.spriteClass = enemy.spriteClass;
            respawnPayload.weaponMode = enemy.spriteWeaponMode;
        }
        broadcastToZone(enemy.zone, 'enemy:spawn', respawnPayload);
    }, respawnDelay);
}

// ============================================================
// RO-Style Derived Stat Calculations (delegates to ro_damage_formulas.js)
// ============================================================
function calculateDerivedStats(stats) {
    return roDerivedStats(stats);
}

/**
 * Full RO pre-renewal physical damage calculation.
 * Handles: HIT/FLEE, Critical, Perfect Dodge, Size Penalty, Element, DEF.
 *
 * @param {Object} attackerStats — effective stats from getEffectiveStats()
 * @param {Object} targetStats — effective stats or enemy stats
 * @param {number} targetHardDef — target's equipment DEF
 * @param {Object} targetInfo — { element, size, race, numAttackers, buffMods }
 * @param {Object} attackerInfo — { weaponType, weaponElement, weaponLevel, buffMods, cardMods }
 * @param {Object} options — { isSkill, skillMultiplier, skillHitBonus, forceHit, skillElement }
 * @returns {Object} { damage, isCritical, isMiss, hitType, element, sizePenalty, elementModifier }
 */
function calculatePhysicalDamage(attackerStats, targetStats, targetHardDef = 0, targetInfo = {}, attackerInfo = {}, options = {}) {
    const attacker = {
        stats: attackerStats,
        weaponATK: attackerStats.weaponATK || 0,
        passiveATK: attackerStats.passiveATK || 0,
        weaponType: attackerInfo.weaponType || 'bare_hand',
        weaponElement: attackerInfo.weaponElement || 'neutral',
        weaponLevel: attackerInfo.weaponLevel || 1,
        buffMods: attackerInfo.buffMods || { atkMultiplier: attackerStats.buffAtkMultiplier || 1.0 },
        cardMods: attackerInfo.cardMods || null,
        passiveRaceATK: attackerInfo.passiveRaceATK || attackerStats.passiveRaceATK || null,
        race: attackerInfo.race || null,
        arrowATK: attackerInfo.arrowATK || 0,
        // Refine ATK (post-DEF bonus, bypasses skill ratio + size)
        refineATK: attackerInfo.refineATK || 0,
        overrefineMax: attackerInfo.overrefineMax || 0,
        // Pass through card fields and mount state for damage formula
        isMounted: attackerInfo.isMounted || false,
        cardNoSizeFix: attackerInfo.cardNoSizeFix || false,
        cardCritRace: attackerInfo.cardCritRace || {},
        cardCriticalLong: attackerInfo.cardCriticalLong || 0,
        critAtkRate: attackerInfo.critAtkRate || 0,
        cardAddClass: attackerInfo.cardAddClass || {},
        cardAddRace2: attackerInfo.cardAddRace2 || {},
        cardLongAtkRate: attackerInfo.cardLongAtkRate || 0,
        cardSkillAtk: attackerInfo.cardSkillAtk || {},
        cardIgnoreDefClass: attackerInfo.cardIgnoreDefClass,
        cardDefRatioAtkClass: attackerInfo.cardDefRatioAtkClass,
        cardAddDamageClass: attackerInfo.cardAddDamageClass || {},
    };

    const target = {
        stats: targetStats,
        hardDef: targetHardDef,
        element: targetInfo.element || { type: 'neutral', level: 1 },
        size: targetInfo.size || 'medium',
        race: targetInfo.race || 'formless',
        numAttackers: targetInfo.numAttackers || 1,
        buffMods: targetInfo.buffMods || { defMultiplier: targetStats.buffDefMultiplier || 1.0 },
        passiveRaceDEF: targetInfo.passiveRaceDEF || null,
        elementResist: targetInfo.elementResist || null,
        modeFlags: targetInfo.modeFlags || null,
        templateId: targetInfo.templateId || null,
        subRace: targetInfo.subRace || null,
        cardDefMods: targetInfo.cardDefMods || null,
        cardSubClass: targetInfo.cardSubClass || null,
        _ensembleVitDefZero: targetInfo._ensembleVitDefZero || false,
    };

    return roPhysicalDamage(attacker, target, options);
}

// ============================================================
// Card Bonus System — rebuild all card bonuses from equipped items
// ============================================================
async function rebuildCardBonuses(player, characterId) {
    // Reset card-specific data
    player.cardBonuses = { str: 0, agi: 0, vit: 0, int: 0, dex: 0, luk: 0, maxHp: 0, maxSp: 0, hit: 0, flee: 0, critical: 0, perfectDodge: 0, atk: 0, def: 0, matk: 0, mdef: 0 };
    player.cardMods = null;
    player.cardDefMods = null;
    player.cardModsRight = null;  // Per-hand card mods for dual wield auto-attacks
    player.cardModsLeft = null;
    player.cardMaxHpRate = 0;
    player.cardMaxSpRate = 0;

    // Phase 1: Extended combat modifiers
    player.cardCritAtkRate = 0;
    player.cardCritRace = {};
    player.cardHpRecovRate = 0;
    player.cardSpRecovRate = 0;
    player.cardCastRate = 0;
    player.cardMatkRate = 0;
    player.cardAspdRate = 0;
    player.cardLongAtkRate = 0;
    player.cardLongAtkDef = 0;
    player.cardAddClass = {};
    player.cardSubClass = {};
    player.cardMagicRace = {};
    player.cardAddRace2 = {};
    player.cardUseSPRate = 0;
    player.cardHealPower = 0;
    player.cardDelayRate = 0;
    player.cardCriticalLong = 0;
    player.cardIgnoreMdefClass = {};
    player.cardIgnoreDefClass = null;
    player.cardDefRatioAtkClass = null;
    player.cardSkillAtk = {};

    // Phase 2: Kill/drain hooks
    player.cardSpGainRace = {};
    player.cardHpGainValue = 0;
    player.cardSpGainValue = 0;
    player.cardExpAddRace = {};
    player.cardGetZenyNum = 0;
    player.cardHpDrainRate = null;
    player.cardSpDrainRate = null;
    player.cardSpDrainValue = 0;

    // Phase 3: Special flags
    player.cardNoSizeFix = false;
    player.cardNoMagicDamage = 0;
    player.cardNoCastCancel = false;
    player.cardNoWalkDelay = false;
    player.cardNoGemStone = false;
    player.cardNoKnockback = false;
    player.cardSplashRange = 0;
    player.cardIntravision = false;
    player.cardRestartFullRecover = false;
    player.cardSpeedRate = 0;
    player.cardUnbreakableArmor = false;
    player.cardUnbreakableWeapon = false;

    // Phase 4: Reflection & periodic
    player.cardMagicDamageReturn = 0;
    player.cardShortWeaponDamageReturn = 0;
    player.cardHpLossRate = null;
    player.cardHpRegenRate = null;
    player.cardSpRegenRate = null;
    player.cardSpVanishRate = null;
    player.cardBreakWeaponRate = 0;
    player.cardBreakArmorRate = 0;

    // Phase 5: Status effect procs
    player.cardAddEff = [];
    player.cardAddEff2 = [];
    player.cardAddEffWhenHit = [];
    player.cardResEff = {};

    // Phase 6: Auto-cast & skill systems
    player.cardAutoSpell = [];
    player.cardAutoSpellWhenHit = [];
    player.cardSkillGrant = [];
    player.cardAddSkillBlow = [];
    player.cardAutobonus = [];

    // Phase 8: Drop modification
    player.cardAddMonsterDropItem = [];
    player.cardAddMonsterDropItemGroup = [];
    player.cardAddItemHealRate = {};
    player.cardAddItemGroupHealRate = {};
    player.cardAddDamageClass = {};
    player.cardAddDefMonster = {};

    // Phase 6: Unique effects
    player.cardComaClass = null;

    try {
        const result = await pool.query(
            `SELECT ci.compounded_cards, i.equip_slot, ci.equipped_position
             FROM character_inventory ci
             JOIN items i ON ci.item_id = i.item_id
             WHERE ci.character_id = $1 AND ci.is_equipped = true
             AND ci.compounded_cards IS NOT NULL AND ci.compounded_cards != '[]'::jsonb`,
            [characterId]
        );

        const combatMods = {};       // Merged (for skills)
        const combatModsRight = {};  // Right-hand weapon cards only (for auto-attacks)
        const combatModsLeft = {};   // Left-hand weapon cards only (for auto-attacks)
        const defenseMods = {};
        let armorElement = null;
        let totalMaxHpRate = 0;
        let totalMaxSpRate = 0;

        for (const row of result.rows) {
            const cards = row.compounded_cards;
            if (!Array.isArray(cards)) continue;

            // Determine which per-hand bucket this equipment's cards go to
            const isRightWeapon = row.equipped_position === 'weapon';
            const isLeftWeapon = row.equipped_position === 'weapon_left';

            for (const cardId of cards) {
                if (!cardId) continue;

                // Flat stat bonuses from card item's DB columns
                const cardDef = itemDefinitions.get(cardId);
                if (cardDef) {
                    player.cardBonuses.str += cardDef.str_bonus || 0;
                    player.cardBonuses.agi += cardDef.agi_bonus || 0;
                    player.cardBonuses.vit += cardDef.vit_bonus || 0;
                    player.cardBonuses.int += cardDef.int_bonus || 0;
                    player.cardBonuses.dex += cardDef.dex_bonus || 0;
                    player.cardBonuses.luk += cardDef.luk_bonus || 0;
                    player.cardBonuses.maxHp += cardDef.max_hp_bonus || 0;
                    player.cardBonuses.maxSp += cardDef.max_sp_bonus || 0;
                    player.cardBonuses.hit += cardDef.hit_bonus || 0;
                    player.cardBonuses.flee += cardDef.flee_bonus || 0;
                    player.cardBonuses.critical += cardDef.critical_bonus || 0;
                    player.cardBonuses.perfectDodge += cardDef.perfect_dodge_bonus || 0;
                    player.cardBonuses.atk += cardDef.atk || 0;
                    player.cardBonuses.def += cardDef.def || 0;
                    player.cardBonuses.matk += cardDef.matk || 0;
                    player.cardBonuses.mdef += cardDef.mdef || 0;
                }

                // Complex effects from parsed scripts
                const effect = CARD_EFFECTS.get(cardId);
                if (effect) {
                    // Always add to merged combatMods (used by skills)
                    for (const [key, val] of Object.entries(effect.combat)) {
                        combatMods[key] = (combatMods[key] || 0) + val;
                    }

                    // Per-hand card mods: weapon cards go to their respective hand
                    if (isRightWeapon) {
                        for (const [key, val] of Object.entries(effect.combat)) {
                            combatModsRight[key] = (combatModsRight[key] || 0) + val;
                        }
                    } else if (isLeftWeapon) {
                        for (const [key, val] of Object.entries(effect.combat)) {
                            combatModsLeft[key] = (combatModsLeft[key] || 0) + val;
                        }
                    } else {
                        // Non-weapon equipment cards apply to BOTH hands
                        for (const [key, val] of Object.entries(effect.combat)) {
                            combatModsRight[key] = (combatModsRight[key] || 0) + val;
                            combatModsLeft[key] = (combatModsLeft[key] || 0) + val;
                        }
                    }

                    for (const [key, val] of Object.entries(effect.defense)) {
                        defenseMods[key] = (defenseMods[key] || 0) + val;
                    }
                    // Armor element — only from armor slot cards
                    if (effect.armorElement && row.equip_slot === 'armor') {
                        armorElement = effect.armorElement;
                    }
                    totalMaxHpRate += effect.maxHpRate || 0;
                    totalMaxSpRate += effect.maxSpRate || 0;

                    // Phase 1: Extended combat modifiers (additive aggregation)
                    player.cardCritAtkRate += effect.critAtkRate || 0;
                    for (const [r, v] of Object.entries(effect.critRace)) player.cardCritRace[r] = (player.cardCritRace[r] || 0) + v;
                    player.cardHpRecovRate += effect.hpRecovRate || 0;
                    player.cardSpRecovRate += effect.spRecovRate || 0;
                    player.cardCastRate += effect.castRate || 0;
                    player.cardMatkRate += effect.matkRate || 0;
                    player.cardAspdRate += effect.aspdRate || 0;
                    player.cardLongAtkRate += effect.longAtkRate || 0;
                    player.cardLongAtkDef += effect.longAtkDef || 0;
                    for (const [c, v] of Object.entries(effect.addClass)) player.cardAddClass[c] = (player.cardAddClass[c] || 0) + v;
                    for (const [c, v] of Object.entries(effect.subClass)) player.cardSubClass[c] = (player.cardSubClass[c] || 0) + v;
                    for (const [r, v] of Object.entries(effect.magicRace)) player.cardMagicRace[r] = (player.cardMagicRace[r] || 0) + v;
                    for (const [r, v] of Object.entries(effect.addRace2)) player.cardAddRace2[r] = (player.cardAddRace2[r] || 0) + v;
                    player.cardUseSPRate += effect.useSPRate || 0;
                    player.cardHealPower += effect.healPower || 0;
                    player.cardDelayRate += effect.delayRate || 0;
                    player.cardCriticalLong += effect.criticalLong || 0;
                    for (const [c, v] of Object.entries(effect.ignoreMdefClass)) player.cardIgnoreMdefClass[c] = (player.cardIgnoreMdefClass[c] || 0) + v;
                    if (effect.ignoreDefClass) player.cardIgnoreDefClass = effect.ignoreDefClass;
                    if (effect.defRatioAtkClass) player.cardDefRatioAtkClass = effect.defRatioAtkClass;
                    for (const [s, v] of Object.entries(effect.skillAtk)) player.cardSkillAtk[s] = (player.cardSkillAtk[s] || 0) + v;
                    if (effect.allStats) {
                        player.cardBonuses.str += effect.allStats;
                        player.cardBonuses.agi += effect.allStats;
                        player.cardBonuses.vit += effect.allStats;
                        player.cardBonuses.int += effect.allStats;
                        player.cardBonuses.dex += effect.allStats;
                        player.cardBonuses.luk += effect.allStats;
                    }

                    // Phase 2: Kill/drain hooks
                    for (const [r, v] of Object.entries(effect.spGainRace)) player.cardSpGainRace[r] = (player.cardSpGainRace[r] || 0) + v;
                    player.cardHpGainValue += effect.hpGainValue || 0;
                    player.cardSpGainValue += effect.spGainValue || 0;
                    for (const [r, v] of Object.entries(effect.expAddRace)) player.cardExpAddRace[r] = (player.cardExpAddRace[r] || 0) + v;
                    player.cardGetZenyNum += effect.getZenyNum || 0;
                    if (effect.hpDrainRate) {
                        if (!player.cardHpDrainRate) player.cardHpDrainRate = { chance: 0, percent: 0 };
                        player.cardHpDrainRate.chance = Math.max(player.cardHpDrainRate.chance, effect.hpDrainRate.chance);
                        player.cardHpDrainRate.percent += effect.hpDrainRate.percent;
                    }
                    if (effect.spDrainRate) {
                        if (!player.cardSpDrainRate) player.cardSpDrainRate = { chance: 0, percent: 0 };
                        player.cardSpDrainRate.chance = Math.max(player.cardSpDrainRate.chance, effect.spDrainRate.chance);
                        player.cardSpDrainRate.percent += effect.spDrainRate.percent;
                    }
                    player.cardSpDrainValue += effect.spDrainValue || 0;

                    // Phase 3: Special flags (OR for booleans, additive for values)
                    if (effect.noSizeFix) player.cardNoSizeFix = true;
                    player.cardNoMagicDamage += effect.noMagicDamage || 0;
                    if (effect.noCastCancel) player.cardNoCastCancel = true;
                    if (effect.noWalkDelay) player.cardNoWalkDelay = true;
                    if (effect.noGemStone) player.cardNoGemStone = true;
                    if (effect.noKnockback) player.cardNoKnockback = true;
                    player.cardSplashRange = Math.max(player.cardSplashRange, effect.splashRange || 0);
                    if (effect.intravision) player.cardIntravision = true;
                    if (effect.restartFullRecover) player.cardRestartFullRecover = true;
                    player.cardSpeedRate += effect.speedRate || 0;
                    if (effect.unbreakableArmor) player.cardUnbreakableArmor = true;
                    if (effect.unbreakableWeapon) player.cardUnbreakableWeapon = true;

                    // Phase 4: Reflection & periodic
                    player.cardMagicDamageReturn += effect.magicDamageReturn || 0;
                    player.cardShortWeaponDamageReturn += effect.shortWeaponDamageReturn || 0;
                    if (effect.hpLossRate) player.cardHpLossRate = effect.hpLossRate;
                    if (effect.hpRegenRate) player.cardHpRegenRate = effect.hpRegenRate;
                    if (effect.spRegenRate) player.cardSpRegenRate = effect.spRegenRate;
                    if (effect.spVanishRate) player.cardSpVanishRate = effect.spVanishRate;
                    player.cardBreakWeaponRate += effect.breakWeaponRate || 0;
                    player.cardBreakArmorRate += effect.breakArmorRate || 0;

                    // Phase 5: Status effect procs (concat arrays)
                    if (effect.addEff.length > 0) player.cardAddEff.push(...effect.addEff);
                    if (effect.addEff2.length > 0) player.cardAddEff2.push(...effect.addEff2);
                    if (effect.addEffWhenHit.length > 0) player.cardAddEffWhenHit.push(...effect.addEffWhenHit);
                    for (const [e, v] of Object.entries(effect.resEff)) player.cardResEff[e] = (player.cardResEff[e] || 0) + v;

                    // Phase 6: Auto-cast & skill systems
                    if (effect.autoSpell.length > 0) player.cardAutoSpell.push(...effect.autoSpell);
                    if (effect.autoSpellWhenHit.length > 0) player.cardAutoSpellWhenHit.push(...effect.autoSpellWhenHit);
                    if (effect.skillGrant.length > 0) player.cardSkillGrant.push(...effect.skillGrant);
                    if (effect.addSkillBlow.length > 0) player.cardAddSkillBlow.push(...effect.addSkillBlow);
                    if (effect.autobonus.length > 0) player.cardAutobonus.push(...effect.autobonus);

                    // Phase 8: Drop modification
                    if (effect.addMonsterDropItem.length > 0) player.cardAddMonsterDropItem.push(...effect.addMonsterDropItem);
                    if (effect.addMonsterDropItemGroup.length > 0) player.cardAddMonsterDropItemGroup.push(...effect.addMonsterDropItemGroup);
                    for (const [id, v] of Object.entries(effect.addItemHealRate)) player.cardAddItemHealRate[id] = (player.cardAddItemHealRate[id] || 0) + v;
                    for (const [g, v] of Object.entries(effect.addItemGroupHealRate)) player.cardAddItemGroupHealRate[g] = (player.cardAddItemGroupHealRate[g] || 0) + v;
                    for (const [id, v] of Object.entries(effect.addDamageClass)) player.cardAddDamageClass[id] = (player.cardAddDamageClass[id] || 0) + v;
                    for (const [id, v] of Object.entries(effect.addDefMonster)) player.cardAddDefMonster[id] = (player.cardAddDefMonster[id] || 0) + v;

                    // Unique
                    if (effect.comaClass) player.cardComaClass = effect.comaClass;

                    // System F: Card skill grants — resolve skill names to IDs
                    if (effect.skillGrant.length > 0) {
                        if (!player.cardGrantedSkills) player.cardGrantedSkills = {};
                        for (const grant of effect.skillGrant) {
                            const skillDef = ALL_SKILLS.find(s => s.name === grant.skill.toLowerCase() ||
                                s.name === grant.skill.replace(/^[A-Z]{2}_/, '').toLowerCase());
                            if (skillDef) {
                                const existing = player.cardGrantedSkills[skillDef.id] || 0;
                                player.cardGrantedSkills[skillDef.id] = Math.max(existing, grant.level);
                            }
                        }
                    }
                }
            }
        }

        player.cardMods = Object.keys(combatMods).length > 0 ? combatMods : null;
        player.cardDefMods = Object.keys(defenseMods).length > 0 ? defenseMods : null;
        player.cardModsRight = Object.keys(combatModsRight).length > 0 ? combatModsRight : null;
        player.cardModsLeft = Object.keys(combatModsLeft).length > 0 ? combatModsLeft : null;

        // Armor element from card (only armor-slot cards can change armor element)
        if (armorElement) {
            player.armorElement = { type: armorElement, level: 1 };
        } else {
            player.armorElement = { type: 'neutral', level: 1 };
        }

        player.cardMaxHpRate = totalMaxHpRate;
        player.cardMaxSpRate = totalMaxSpRate;

        // ── Phase 7: Evaluate conditional card effects ──
        // Cards with readparam()/getrefine() as bonus values need player context
        await evaluateConditionalCardBonuses(player, characterId, result.rows, combatMods, defenseMods, combatModsRight, combatModsLeft);

        // Re-apply combat/defense mods after conditional evaluation may have changed them
        player.cardMods = Object.keys(combatMods).length > 0 ? combatMods : null;
        player.cardDefMods = Object.keys(defenseMods).length > 0 ? defenseMods : null;
        player.cardModsRight = Object.keys(combatModsRight).length > 0 ? combatModsRight : null;
        player.cardModsLeft = Object.keys(combatModsLeft).length > 0 ? combatModsLeft : null;

        const hasAny = player.cardMods || player.cardDefMods || armorElement ||
            Object.values(player.cardBonuses).some(v => v !== 0);
        if (hasAny) {
            logger.info(`[CARDS] Rebuilt card bonuses for char ${characterId}: stats=${JSON.stringify(player.cardBonuses)}, combat=${JSON.stringify(combatMods)}, defense=${JSON.stringify(defenseMods)}${armorElement ? `, armorEle=${armorElement}` : ''}`);
        }
    } catch (err) {
        logger.warn(`[CARDS] Failed to rebuild card bonuses for char ${characterId}: ${err.message}`);
    }
}

// ============================================================
// Phase 7: Conditional Card Effect Evaluation
// Handles cards with getrefine()/readparam() in bonus values
// and if() conditions gating bonus application
// ============================================================
async function evaluateConditionalCardBonuses(player, characterId, equippedRows, combatMods, defenseMods, combatModsRight, combatModsLeft) {
    // Get refine levels of equipped items
    const refineResult = await pool.query(
        `SELECT ci.item_id, ci.equipped_position, ci.compounded_cards, ci.refine_level, i.equip_slot
         FROM character_inventory ci
         JOIN items i ON ci.item_id = i.item_id
         WHERE ci.character_id = $1 AND ci.is_equipped = true`,
        [characterId]
    );
    const refineBySlot = {};
    for (const row of refineResult.rows) {
        refineBySlot[row.equipped_position || row.equip_slot] = row.refine_level || 0;
    }

    // Player base stats for readparam()
    const pStr = player.stats.str || 1;
    const pAgi = player.stats.agi || 1;
    const pVit = player.stats.vit || 1;
    const pInt = player.stats.int || player.stats.int_stat || 1;
    const pDex = player.stats.dex || 1;
    const pLuk = player.stats.luk || 1;
    const pLevel = player.stats.level || 1;
    const jobClass = player.jobClass || 'novice';

    // Process each equipped item's compounded cards for conditional effects
    for (const row of equippedRows) {
        const cards = row.compounded_cards;
        if (!Array.isArray(cards)) continue;
        const refine = refineBySlot[row.equipped_position || row.equip_slot] || 0;

        for (const cardId of cards) {
            if (!cardId) continue;
            const cardDef = itemDefinitions.get(cardId);
            if (!cardDef || !cardDef.script) continue;
            const script = cardDef.script;

            // Skip cards that don't need conditional evaluation
            if (!script.includes('getrefine') && !script.includes('readparam') && !script.includes('BaseClass') && !script.includes('BaseJob') && !script.includes('getskilllv')) continue;

            // ── readparam-as-value cards (stat scales with another stat) ──
            // Pattern: bonus bStat,readparam(bOtherStat)/N;
            const paramValueMatch = script.match(/bonus\s+b(\w+)\s*,\s*readparam\(b(\w+)\)\s*\/\s*(\d+)/);
            if (paramValueMatch) {
                const targetStat = paramValueMatch[1].toLowerCase();
                const sourceStat = paramValueMatch[2].toLowerCase();
                const divisor = parseInt(paramValueMatch[3]);
                const statMap = { str: pStr, agi: pAgi, vit: pVit, int: pInt, dex: pDex, luk: pLuk };
                const sourceVal = statMap[sourceStat] || 0;
                const bonus = Math.floor(sourceVal / divisor);
                if (bonus > 0 && player.cardBonuses[targetStat] !== undefined) {
                    player.cardBonuses[targetStat] += bonus;
                }
            }

            // ── getrefine()-as-value cards (stat scales with refine level) ──
            // Pattern: bonus bStat,getrefine()-N;
            for (const rm of script.matchAll(/bonus\s+b(\w+)\s*,\s*getrefine\(\)\s*(?:-\s*(\d+))?/g)) {
                const targetStat = rm[1].toLowerCase();
                const offset = rm[2] ? parseInt(rm[2]) : 0;
                const bonus = refine - offset;
                if (bonus > 0 && player.cardBonuses[targetStat] !== undefined) {
                    player.cardBonuses[targetStat] += bonus;
                }
                // Handle bCritical with getrefine() (Green Maiden Card)
                if (targetStat === 'critical' && bonus > 0) {
                    player.cardBonuses.critical += bonus;
                }
            }

            // ── if(getrefine()>=N) conditional bonuses ──
            const refineCondMatches = [...script.matchAll(/if\s*\(\s*getrefine\(\)\s*([><=!]+)\s*(\d+)\s*\)/g)];
            for (const rcm of refineCondMatches) {
                const op = rcm[1];
                const threshold = parseInt(rcm[2]);
                let conditionMet = false;
                if (op === '>=' || op === '>') conditionMet = op === '>=' ? refine >= threshold : refine > threshold;
                else if (op === '<=' || op === '<') conditionMet = op === '<=' ? refine <= threshold : refine < threshold;
                else if (op === '==' || op === '===') conditionMet = refine === threshold;

                if (conditionMet) {
                    // Extract the bonus block after this condition
                    const condIdx = script.indexOf(rcm[0]);
                    const afterCond = script.substring(condIdx + rcm[0].length);
                    // Parse bonuses in the conditional block (up to next if/else/})
                    const blockEnd = afterCond.search(/\bif\b|^\s*else\b|^\s*\}/m);
                    const block = blockEnd > 0 ? afterCond.substring(0, blockEnd) : afterCond;
                    applyConditionalBonusBlock(block, player, combatMods, defenseMods, row, combatModsRight, combatModsLeft);
                }
            }

            // ── if(readparam(bX)>=N) conditional bonuses ──
            const paramCondMatches = [...script.matchAll(/if\s*\(\s*readparam\(b(\w+)\)\s*>=\s*(\d+)\s*\)/g)];
            for (const pcm of paramCondMatches) {
                const stat = pcm[1].toLowerCase();
                const threshold = parseInt(pcm[2]);
                const statMap = { str: pStr, agi: pAgi, vit: pVit, int: pInt, dex: pDex, luk: pLuk };
                const val = statMap[stat] || 0;
                if (val >= threshold) {
                    const condIdx = script.indexOf(pcm[0]);
                    const afterCond = script.substring(condIdx + pcm[0].length);
                    const blockEnd = afterCond.search(/\bif\b|^\s*else\b|^\s*\}/m);
                    const block = blockEnd > 0 ? afterCond.substring(0, blockEnd) : afterCond;
                    applyConditionalBonusBlock(block, player, combatMods, defenseMods, row, combatModsRight, combatModsLeft);
                }
            }

            // ── if(BaseClass == Job_X) conditional bonuses ──
            const classCondMatches = [...script.matchAll(/if\s*\(\s*(?:BaseClass|BaseJob)\s*==\s*Job_(\w+)\s*\)/g)];
            const BASE_CLASS_MAP = {
                'Swordman': ['swordsman', 'knight', 'crusader', 'lord_knight', 'paladin'],
                'Mage': ['mage', 'wizard', 'sage', 'high_wizard', 'scholar'],
                'Archer': ['archer', 'hunter', 'bard', 'dancer', 'sniper', 'minstrel', 'gypsy'],
                'Merchant': ['merchant', 'blacksmith', 'alchemist', 'whitesmith', 'biochemist'],
                'Thief': ['thief', 'assassin', 'rogue', 'assassin_cross', 'stalker'],
                'Acolyte': ['acolyte', 'priest', 'monk', 'high_priest', 'champion'],
                'Novice': ['novice', 'high_novice', 'super_novice'],
                'Knight': ['knight', 'lord_knight'],
                'Assassin': ['assassin', 'assassin_cross'],
                'Priest': ['priest', 'high_priest'],
                'Sage': ['sage', 'scholar'],
                'Rogue': ['rogue', 'stalker'],
                'Dancer': ['dancer', 'gypsy'],
                'SuperNovice': ['super_novice'],
            };
            for (const ccm of classCondMatches) {
                const reqClass = ccm[1];
                const allowedClasses = BASE_CLASS_MAP[reqClass] || [reqClass.toLowerCase()];
                if (allowedClasses.includes(jobClass)) {
                    const condIdx = script.indexOf(ccm[0]);
                    const afterCond = script.substring(condIdx + ccm[0].length);
                    const blockEnd = afterCond.search(/\bif\b|^\s*else\b|^\s*\}/m);
                    const block = blockEnd > 0 ? afterCond.substring(0, blockEnd) : afterCond;
                    applyConditionalBonusBlock(block, player, combatMods, defenseMods, row, combatModsRight, combatModsLeft);
                }
            }
        }
    }
}

// Apply bonuses from a conditional block (reuses same regex patterns as parseCardScript)
function applyConditionalBonusBlock(block, player, combatMods, defenseMods, row, combatModsRight, combatModsLeft) {
    const { RC_MAP, ELE_MAP, SIZE_MAP, EFF_MAP } = require('./ro_card_effects');
    const ALL_RACES = ['formless', 'undead', 'brute', 'plant', 'insect', 'fish', 'demon', 'demihuman', 'angel', 'dragon'];

    const isRightWeapon = row.equipped_position === 'weapon';
    const isLeftWeapon = row.equipped_position === 'weapon_left';

    // Flat stat bonuses
    for (const m of block.matchAll(/bonus\s+b(Str|Agi|Vit|Int|Dex|Luk)\s*,\s*(-?\d+)/g)) {
        const stat = m[1].toLowerCase();
        const val = parseInt(m[2]);
        if (player.cardBonuses[stat] !== undefined) player.cardBonuses[stat] += val;
    }
    for (const m of block.matchAll(/bonus\s+bBaseAtk\s*,\s*(-?\d+)/g)) player.cardBonuses.atk += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bDef\s*,\s*(-?\d+)/g)) player.cardBonuses.def += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bMdef\s*,\s*(-?\d+)/g)) player.cardBonuses.mdef += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bHit\s*,\s*(-?\d+)/g)) player.cardBonuses.hit += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bFlee\s*,\s*(-?\d+)/g)) player.cardBonuses.flee += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bFlee2\s*,\s*(-?\d+)/g)) player.cardBonuses.perfectDodge += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bCritical\s*,\s*(-?\d+)/g)) player.cardBonuses.critical += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bMaxHP\s*,\s*(-?\d+)/g)) player.cardBonuses.maxHp += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bMaxSP\s*,\s*(-?\d+)/g)) player.cardBonuses.maxSp += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bMaxHPrate\s*,\s*(-?\d+)/g)) player.cardMaxHpRate += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bMaxSPrate\s*,\s*(-?\d+)/g)) player.cardMaxSpRate += parseInt(m[1]);

    // Combat mods
    for (const m of block.matchAll(/bonus2\s+bSubEle\s*,\s*(\w+)\s*,\s*(-?\d+)/g)) {
        const ele = ELE_MAP[m[1]]; const val = parseInt(m[2]);
        if (ele) defenseMods[`ele_${ele}`] = (defenseMods[`ele_${ele}`] || 0) + val;
    }
    for (const m of block.matchAll(/bonus2\s+bCriticalAddRace\s*,\s*(\w+)\s*,\s*(-?\d+)/g)) {
        const race = RC_MAP[m[1]]; const val = parseInt(m[2]);
        if (race) player.cardCritRace[race] = (player.cardCritRace[race] || 0) + val;
    }
    for (const m of block.matchAll(/bonus2\s+bSkillAtk\s*,\s*"?(\w+)"?\s*,\s*(-?\d+)/g)) {
        player.cardSkillAtk[m[1]] = (player.cardSkillAtk[m[1]] || 0) + parseInt(m[2]);
    }

    // Flags
    if (/bonus\s+bUnbreakableArmor/.test(block)) player.cardUnbreakableArmor = true;
    if (/bonus\s+bUnbreakableWeapon/.test(block)) player.cardUnbreakableWeapon = true;

    // HP/SP regen rates
    for (const m of block.matchAll(/bonus\s+bHPrecovRate\s*,\s*(-?\d+)/g)) player.cardHpRecovRate += parseInt(m[1]);
    for (const m of block.matchAll(/bonus\s+bSPrecovRate\s*,\s*(-?\d+)/g)) player.cardSpRecovRate += parseInt(m[1]);

    // MATK rate
    for (const m of block.matchAll(/bonus\s+bMatkRate\s*,\s*(-?\d+)/g)) player.cardMatkRate += parseInt(m[1]);

    // AddClass
    for (const m of block.matchAll(/bonus2\s+bAddClass\s*,\s*(\w+)\s*,\s*(-?\d+)/g)) {
        const { CLASS_MAP } = require('./ro_card_effects');
        const cls = CLASS_MAP[m[1]]; const val = parseInt(m[2]);
        if (cls) {
            if (cls === 'all') { player.cardAddClass.boss = (player.cardAddClass.boss || 0) + val; player.cardAddClass.normal = (player.cardAddClass.normal || 0) + val; }
            else player.cardAddClass[cls] = (player.cardAddClass[cls] || 0) + val;
        }
    }

    // Ignore MDEF
    for (const m of block.matchAll(/bonus2\s+bIgnoreMdefClassRate\s*,\s*(\w+)\s*,\s*(-?\d+)/g)) {
        const { CLASS_MAP } = require('./ro_card_effects');
        const cls = CLASS_MAP[m[1]]; const val = parseInt(m[2]);
        if (cls) player.cardIgnoreMdefClass[cls] = (player.cardIgnoreMdefClass[cls] || 0) + val;
    }
}

// ============================================================
// Card Effect Hooks — Called from combat, kill, regen, etc.
// Phases 2-8: Process card effects at the right moments
// ============================================================

/**
 * Phase 2: Process card kill hooks (SP/HP gain, Zeny, EXP bonus)
 * Called after a monster is killed, BEFORE processExpGain for EXP bonuses
 * @returns {object} { bonusBaseExp, bonusJobExp } - EXP multiplier adjustments
 */
function processCardKillHooks(attacker, enemy, attackerId, io) {
    const monsterRace = enemy.race || 'formless';
    const killerSocket = io.sockets.sockets.get(attacker.socketId);
    let hpGained = 0, spGained = 0;

    // bSPGainRace: gain SP on kill by race (Zombie Master Card, etc.)
    const spGainRace = attacker.cardSpGainRace || {};
    const spFromRace = spGainRace[monsterRace] || 0;
    if (spFromRace > 0) spGained += spFromRace;

    // bHPGainValue: flat HP on kill
    if (attacker.cardHpGainValue > 0) hpGained += attacker.cardHpGainValue;

    // bSPGainValue: flat SP on kill
    if (attacker.cardSpGainValue > 0) spGained += attacker.cardSpGainValue;

    // Apply HP/SP gains
    if (hpGained > 0 && !attacker.isDead) {
        attacker.health = Math.min(attacker.maxHealth, attacker.health + hpGained);
    }
    if (spGained > 0 && !attacker.isDead) {
        attacker.mana = Math.min(attacker.maxMana, attacker.mana + spGained);
    }

    // bGetZenyNum: random Zeny on kill (Cramp Card)
    if (attacker.cardGetZenyNum > 0) {
        const zeny = Math.floor(Math.random() * attacker.cardGetZenyNum) + 1;
        attacker.zeny = (attacker.zeny || 0) + zeny;
        attacker.zuzucoin = attacker.zeny; // Keep in sync
    }

    // bExpAddRace: EXP bonus % by race
    const expBonus = (attacker.cardExpAddRace || {})[monsterRace] || 0;

    return { expBonusPercent: expBonus };
}

/**
 * Phase 2: Process card drain effects on each auto-attack hit
 * Called after damage is dealt in auto-attack tick
 */
function processCardDrainEffects(attacker, damage, attackerId) {
    // bHPDrainRate: chance% to drain percent% of damage as HP
    if (attacker.cardHpDrainRate && damage > 0) {
        if (Math.random() * 100 < attacker.cardHpDrainRate.chance) {
            const hpDrain = Math.max(1, Math.floor(damage * attacker.cardHpDrainRate.percent / 100));
            attacker.health = Math.min(attacker.maxHealth, attacker.health + hpDrain);
        }
    }

    // bSPDrainRate: chance% to drain percent% of damage as SP
    if (attacker.cardSpDrainRate && damage > 0) {
        if (Math.random() * 100 < attacker.cardSpDrainRate.chance) {
            const spDrain = Math.max(1, Math.floor(damage * attacker.cardSpDrainRate.percent / 100));
            attacker.mana = Math.min(attacker.maxMana, attacker.mana + spDrain);
        }
    }

    // bSPDrainValue: flat SP per hit (positive = gain, negative = lose)
    if (attacker.cardSpDrainValue !== 0 && damage > 0) {
        attacker.mana = Math.max(0, Math.min(attacker.maxMana, attacker.mana + attacker.cardSpDrainValue));
    }
}

/**
 * Phase 5: Process card status effect procs on auto-attack
 * Called after damage is dealt in auto-attack tick
 */
function processCardStatusProcsOnAttack(attacker, target, targetIsEnemy) {
    if (!attacker.cardAddEff || attacker.cardAddEff.length === 0) return;
    // Boss immunity check
    if (targetIsEnemy && target.modeFlags && target.modeFlags.statusImmune) return;

    for (const proc of attacker.cardAddEff) {
        // Chance is in 1/10000 (rAthena convention)
        if (Math.random() * 10000 < proc.chance) {
            // Use the status effect system if available
            if (typeof applyStatusEffect === 'function') {
                applyStatusEffect(attacker, target, proc.effect, 10000); // 100% base chance (already passed RNG)
            } else if (target.activeStatusEffects && !target.activeStatusEffects.has(proc.effect)) {
                // Fallback: simple application
                target.activeStatusEffects.set(proc.effect, {
                    type: proc.effect, appliedAt: Date.now(), duration: 5000,
                    expiresAt: Date.now() + 5000, sourceId: attacker.characterId || 0
                });
            }
        }
    }

    // bAddEff2: inflict status on SELF
    if (attacker.cardAddEff2 && attacker.cardAddEff2.length > 0) {
        for (const proc of attacker.cardAddEff2) {
            if (Math.random() * 10000 < proc.chance) {
                if (typeof applyStatusEffect === 'function') {
                    applyStatusEffect(attacker, attacker, proc.effect, 10000);
                }
            }
        }
    }
}

/**
 * Phase 5: Process card status procs when being hit
 */
function processCardStatusProcsWhenHit(target, attacker, attackerIsEnemy) {
    if (!target.cardAddEffWhenHit || target.cardAddEffWhenHit.length === 0) return;
    // Can't proc on boss attackers
    if (attackerIsEnemy && attacker.modeFlags && attacker.modeFlags.statusImmune) return;

    for (const proc of target.cardAddEffWhenHit) {
        if (Math.random() * 10000 < proc.chance) {
            if (typeof applyStatusEffect === 'function') {
                applyStatusEffect(target, attacker, proc.effect, 10000);
            } else if (attacker.activeStatusEffects && !attacker.activeStatusEffects.has(proc.effect)) {
                attacker.activeStatusEffects.set(proc.effect, {
                    type: proc.effect, appliedAt: Date.now(), duration: 5000,
                    expiresAt: Date.now() + 5000, sourceId: target.characterId || 0
                });
            }
        }
    }
}

/**
 * Phase 4: Process melee damage reflection (Orc Lord, High Orc cards)
 * Returns reflected damage amount
 */
function processCardMeleeReflection(target, damage) {
    if (!target.cardShortWeaponDamageReturn || target.cardShortWeaponDamageReturn <= 0) return 0;
    return Math.max(1, Math.floor(damage * target.cardShortWeaponDamageReturn / 100));
}

/**
 * Phase 4: Process magic damage reflection (Maya Card)
 * Returns reflected damage amount
 */
function processCardMagicReflection(target, damage) {
    if (!target.cardMagicDamageReturn || target.cardMagicDamageReturn <= 0) return 0;
    return Math.max(1, Math.floor(damage * target.cardMagicDamageReturn / 100));
}

/**
 * System K: Check if observer can see a hidden target (cardIntravision)
 * Returns true if the target is visible to the observer
 */
function canSeeHiddenTarget(observer, target) {
    const targetMods = getCombinedModifiers(target);
    if (!targetMods.isHidden) return true; // Not hidden, always visible
    if (observer.cardIntravision) return true; // Maya Purple Card
    return false;
}

/**
 * System: Parse ammo script for status effect procs (bonus2 bAddEff,Eff_X,rate)
 * Returns array of { status, rate } where rate is a percentage (e.g., 10 = 10%)
 */
function parseAmmoStatusProcs(script) {
    if (!script) return [];
    const procs = [];
    const re = /bonus2\s+bAddEff\s*,\s*Eff_(\w+)\s*,\s*(\d+)/gi;
    let m;
    while ((m = re.exec(script)) !== null) {
        procs.push({ status: m[1].toLowerCase(), rate: parseInt(m[2]) / 100 });
    }
    return procs;
}

/**
 * System: Recalculate effective weapon element based on RO priority chain
 * Priority: Endow buff > Arrow element (if non-neutral) > Weapon element
 * Endow is already handled by getCombinedModifiers().weaponElement in getAttackerInfo()
 * This function sets player.weaponElement to include arrow override above base weapon.
 */
function recalcEffectiveWeaponElement(player) {
    let effectiveElement = (player.equippedWeaponRight && player.equippedWeaponRight.element) || 'neutral';
    if (player.equippedAmmo && player.equippedAmmo.element !== 'neutral' && player.weaponType === 'bow') {
        effectiveElement = player.equippedAmmo.element;
    }
    player.weaponElement = effectiveElement;
}

/**
 * System: Consume equipped ammo (1 per auto-attack or skill cast)
 * Returns true if consumed, false if no ammo equipped
 */
async function consumeAmmo(player, characterId, amount, io) {
    if (!player.equippedAmmo) return false;
    player.equippedAmmo.quantity -= amount;
    if (player.equippedAmmo.quantity <= 0) {
        await pool.query('DELETE FROM character_inventory WHERE inventory_id = $1', [player.equippedAmmo.inventoryId]);
        player.equippedAmmo = null;
        recalcEffectiveWeaponElement(player);
        const sock = io.sockets.sockets.get(player.socketId);
        if (sock) {
            sock.emit('ammo:exhausted', { message: 'You have run out of arrows.' });
            sock.emit('ammo:unequipped', {});
        }
        return true;
    }
    await pool.query('UPDATE character_inventory SET quantity = quantity - $1 WHERE inventory_id = $2', [amount, player.equippedAmmo.inventoryId]);
    return true;
}

/**
 * System B: Knockback target N cells away from source position
 * Returns new position or null if target is immune
 */
function knockbackTarget(target, sourceX, sourceY, cells, zone, io) {
    if (!target || !cells || cells <= 0) return null;
    // Boss immunity
    if (target.modeFlags && target.modeFlags.isBoss) return null;
    // bNoKnockback card (RSX-0806)
    if (target.cardNoKnockback) return null;

    const targetX = target.x || 0;
    const targetY = target.y || 0;
    const targetZ = target.z || 0;

    // Calculate direction vector from source to target (push away from source)
    let dx = targetX - sourceX;
    let dy = targetY - sourceY;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < 1) { dx = -1; dy = 0; } // Same position → push west (default, normalized)
    else { dx = dx / dist; dy = dy / dist; }

    // Move target by `cells` * cell size (50 UE units per cell, matching codebase standard)
    // Check each cell step for Ice Wall collision — stop at wall edge
    const cellSize = 50;
    let finalX = targetX, finalY = targetY;
    for (let c = 1; c <= cells; c++) {
        const stepX = targetX + Math.floor(dx * c * cellSize);
        const stepY = targetY + Math.floor(dy * c * cellSize);
        let blocked = false;
        for (const [, eff] of activeGroundEffects.entries()) {
            if (eff.type !== 'ice_wall' || eff.zone !== zone) continue;
            if (Date.now() >= eff.expiresAt) continue;
            const iwdx = stepX - eff.x, iwdy = stepY - eff.y;
            if (Math.sqrt(iwdx * iwdx + iwdy * iwdy) <= (eff.radius || 125)) {
                blocked = true;
                break;
            }
        }
        if (blocked) break;
        finalX = stepX;
        finalY = stepY;
    }

    // Update target position
    target.x = finalX;
    target.y = finalY;

    // Reset NavMesh path after forced movement (enemies only)
    if (target._navPath) {
        target._navPath = [];
        target._navPathIdx = 0;
        target._navPathTarget = null;
    }

    // Close Confine breaks on knockback (RO Classic pre-renewal)
    if (target.activeBuffs && target.activeBuffs.some(b => b.name === 'close_confine')) {
        breakCloseConfine(target, zone, io, 'knockback');
    }

    // Broadcast knockback event
    const targetId = target.enemyId || target.characterId || 0;
    const isEnemy = !!target.enemyId;
    broadcastToZone(zone, 'combat:knockback', {
        targetId, isEnemy, newX: finalX, newY: finalY, newZ: targetZ, cells,
        sourceX, sourceY
    });

    return { x: finalX, y: finalY, z: targetZ };
}

/**
 * System G: Process autobonus procs on attack (Vanberk, Isilla, Atroce)
 * Applies temporary stat bonuses as buffs when proc triggers
 */
function processAutobonusOnAttack(player, characterId) {
    if (!player.cardAutobonus || player.cardAutobonus.length === 0) return;
    for (let i = 0; i < player.cardAutobonus.length; i++) {
        const ab = player.cardAutobonus[i];
        if (Math.random() * 10000 >= ab.chance) continue;
        // Parse the bonus script for stat bonuses
        const bonuses = parseAutobonusScript(ab.bonusScript);
        if (!bonuses) continue;
        // Apply as a temporary buff
        const buffName = `autobonus_${i}`;
        const buffDef = {
            name: buffName, duration: ab.duration,
            modifiers: bonuses, stackRule: 'refresh',
            category: 'buff', displayName: 'Auto Bonus'
        };
        applyBuff(player, buffDef);
        logger.info(`[AUTOBONUS] ${player.characterName} triggered autobonus ${i} for ${ab.duration}ms`);
    }
}

/**
 * System G: Process autobonus2 procs when hit (Hodremlin, Ice Titan)
 */
function processAutobonusWhenHit(player, characterId) {
    if (!player.cardAutobonus || player.cardAutobonus.length === 0) return;
    // autobonus2 entries are stored in the same array with trigger info from the parser
    // For now, process all as potential when-hit triggers
    for (let i = 0; i < player.cardAutobonus.length; i++) {
        const ab = player.cardAutobonus[i];
        if (Math.random() * 10000 >= ab.chance) continue;
        const bonuses = parseAutobonusScript(ab.bonusScript);
        if (!bonuses) continue;
        const buffName = `autobonus_${i}`;
        const buffDef = {
            name: buffName, duration: ab.duration,
            modifiers: bonuses, stackRule: 'refresh',
            category: 'buff', displayName: 'Auto Bonus'
        };
        applyBuff(player, buffDef);
    }
}

/**
 * Parse an autobonus script string like "{ bonus bCritical,100; }" into modifier object
 */
function parseAutobonusScript(script) {
    if (!script) return null;
    const mods = {};
    // bonus bCritical,N
    const critMatch = script.match(/bonus\s+bCritical\s*,\s*(-?\d+)/);
    if (critMatch) mods.bonusCritical = parseInt(critMatch[1]);
    // bonus bCastrate,N
    const castMatch = script.match(/bonus\s+bCastrate\s*,\s*(-?\d+)/);
    if (castMatch) mods.castRateBonus = parseInt(castMatch[1]);
    // bonus bFlee,N
    const fleeMatch = script.match(/bonus\s+bFlee\s*,\s*(-?\d+)/);
    if (fleeMatch) mods.bonusFlee = parseInt(fleeMatch[1]);
    // bonus bFlee2,N (Perfect Dodge)
    const flee2Match = script.match(/bonus\s+bFlee2\s*,\s*(-?\d+)/);
    if (flee2Match) mods.bonusPerfectDodge = parseInt(flee2Match[1]);
    // bonus bDef,N
    const defMatch = script.match(/bonus\s+bDef\s*,\s*(-?\d+)/);
    if (defMatch) mods.bonusDef = parseInt(defMatch[1]);
    // bonus bAspdRate,N
    const aspdMatch = script.match(/bonus\s+bAspdRate\s*,\s*(-?\d+)/);
    if (aspdMatch) mods.aspdMultiplier = 1 + parseInt(aspdMatch[1]) / 100;
    // bonus bAllStats,N
    const allMatch = script.match(/bonus\s+bAllStats\s*,\s*(-?\d+)/);
    if (allMatch) {
        const v = parseInt(allMatch[1]);
        mods.strBonus = v; mods.agiBonus = v; mods.vitBonus = v;
        mods.intBonus = v; mods.dexBonus = v; mods.lukBonus = v;
    }
    return Object.keys(mods).length > 0 ? mods : null;
}

/**
 * System E: Process card auto-spell on attack (bAutoSpell)
 * Called after a successful auto-attack hit. No SP, no cast time, no gems.
 */
function processCardAutoSpellOnAttack(attacker, target, targetIsEnemy, zone, io) {
    if (!attacker.cardAutoSpell || attacker.cardAutoSpell.length === 0) return;
    for (const proc of attacker.cardAutoSpell) {
        if (Math.random() * 1000 >= proc.chance) continue;
        const level = resolveAutoSpellLevel(proc.level, attacker);
        executeAutoSpellEffect(attacker, target, targetIsEnemy, proc.skill, level, zone, io);
    }
}

/**
 * System E: Process card auto-spell when hit (bAutoSpellWhenHit)
 * Called when player takes physical damage. No SP, no cast time, no gems.
 */
function processCardAutoSpellWhenHit(target, attacker, attackerIsEnemy, zone, io) {
    if (!target.cardAutoSpellWhenHit || target.cardAutoSpellWhenHit.length === 0) return;
    for (const proc of target.cardAutoSpellWhenHit) {
        if (Math.random() * 1000 >= proc.chance) continue;
        const level = resolveAutoSpellLevel(proc.level, target);
        // Offensive skills target the attacker, self/support skills target self
        const isOffensive = isAutoSpellOffensive(proc.skill);
        if (isOffensive) {
            executeAutoSpellEffect(target, attacker, attackerIsEnemy, proc.skill, level, zone, io);
        } else {
            // Self-targeted (Gloria, Kyrie, Auto Guard, Heal on self, etc.)
            executeAutoSpellEffect(target, target, false, proc.skill, level, zone, io);
        }
    }
}

/**
 * Resolve auto-spell level — handles expressions like "3+7*(getskilllv("WZ_JUPITEL") == 10)"
 */
function resolveAutoSpellLevel(levelExpr, caster) {
    if (typeof levelExpr === 'number') return levelExpr;
    const str = String(levelExpr).trim();
    // Simple integer
    const simple = parseInt(str);
    if (!isNaN(simple) && String(simple) === str) return simple;
    // Expression with getskilllv — resolve skill level
    try {
        let resolved = str;
        resolved = resolved.replace(/getskilllv\("(\w+)"\)/g, (_, skillName) => {
            // Look up skill ID from name, then check caster's learned skills
            const skillDef = ALL_SKILLS.find(s => s.name === skillName.toLowerCase());
            if (!skillDef || !caster.learnedSkills) return '0';
            return String(caster.learnedSkills[skillDef.id] || 0);
        });
        // Evaluate safe math expression (only +, -, *, ==, numbers)
        const safeExpr = resolved.replace(/[^0-9+\-*/%()= ]/g, '');
        if (safeExpr.length > 0) {
            const result = Function('"use strict"; return (' + safeExpr + ')')();
            return Math.max(1, Math.floor(result));
        }
    } catch (e) { /* fallback */ }
    return parseInt(str) || 1;
}

/**
 * Check if a skill is offensive (targets enemy) vs self/support
 */
function isAutoSpellOffensive(skillName) {
    const SELF_SKILLS = new Set([
        'PR_GLORIA', 'PR_KYRIE', 'SM_ENDURE', 'AL_HEAL', 'AL_BLESSING',
        'AL_INCAGI', 'CR_AUTOGUARD', 'AC_CONCENTRATION', 'MG_SIGHT',
        'PR_MAGNIFICAT', 'PR_SUFFRAGIUM', 'HP_ASSUMPTIO', 'PR_LEXDIVINA'
    ]);
    return !SELF_SKILLS.has(skillName);
}

/**
 * Execute an auto-spell effect (damage, heal, or buff) without SP/cast/gems
 */
function executeAutoSpellEffect(caster, target, targetIsEnemy, skillName, level, zone, io) {
    if (!caster || !target || !zone || !io) return;

    // Look up skill data
    const skillDef = ALL_SKILLS.find(s =>
        s.name === skillName.toLowerCase() ||
        s.name === skillName.replace(/^[A-Z]{2}_/, '').toLowerCase()
    );

    if (!skillDef) {
        // Skill not in our data — log and skip
        logger.debug(`[AUTOCAST] Skill ${skillName} not found in ro_skill_data, skipping`);
        return;
    }

    const levelData = skillDef.levels ? skillDef.levels[Math.min(level - 1, skillDef.levels.length - 1)] : null;
    const multiplier = levelData ? (levelData.effectValue || levelData.damagePercent || 100) : 100;
    const casterId = caster.characterId || caster.enemyId || 0;
    const targetId = target.characterId || target.enemyId || 0;

    // Determine if this is a physical or magical skill
    const isMagical = skillDef.type === 'offensive_magic' || skillDef.element === 'fire' ||
        skillDef.element === 'water' || skillDef.element === 'wind' || skillDef.element === 'earth' ||
        skillDef.element === 'ghost' || skillDef.element === 'holy';

    if (skillDef.type === 'heal' || skillName === 'AL_HEAL') {
        // Heal auto-cast (Loli Ruri, Enchanted Peach Tree, Vitata granted skill)
        const healAmt = Math.floor(((caster.stats?.level || 1) + (caster.stats?.int || 1)) / 8) * (4 + level * 8);
        if (target.health !== undefined) {
            target.health = Math.min(target.maxHealth || target.health, target.health + healAmt);
        }
        broadcastToZone(zone, 'skill:effect_damage', {
            attackerId: casterId, targetId, skillId: skillDef.id, skillName: skillDef.displayName || skillName,
            damage: 0, hitType: 'heal', healAmount: healAmt, element: 'holy',
            isEnemy: targetIsEnemy, targetHealth: target.health || 0, targetMaxHealth: target.maxHealth || 0,
            hitNumber: 1, totalHits: 1
        });
    } else if (skillDef.type === 'buff' || skillDef.type === 'support' || !isMagical && !targetIsEnemy) {
        // Buff auto-cast (Gloria, Kyrie, Auto Guard, Blessing, etc.)
        // Apply as a buff if we have a handler for it
        const buffName = skillName.toLowerCase().replace(/^[a-z]{2}_/, '');
        logger.info(`[AUTOCAST] Buff ${skillName} Lv${level} triggered on ${target.characterName || target.name || targetId}`);
        // For now, broadcast the visual — full buff application would need per-skill handlers
        broadcastToZone(zone, 'skill:cast_complete', { casterId, skillId: skillDef.id, targetType: skillDef.targetType });
    } else if (isMagical && targetIsEnemy) {
        // Magical damage auto-cast (bolts, Meteor Storm, etc.)
        const effectiveStats = caster.stats ? getEffectiveStats(caster) : caster;
        const attackerInfo = caster.characterId ? getAttackerInfo(caster) : { weaponType: 'bare_hand', weaponElement: 'neutral', weaponLevel: 1, buffMods: {}, cardMods: null, race: 'demihuman' };
        const targetInfo = target.enemyId ? getEnemyTargetInfo(target) : { element: target.element || { type: 'neutral', level: 1 }, size: 'medium', race: target.race || 'formless', numAttackers: 1, buffMods: {} };
        const skillElement = skillDef.element && skillDef.element !== 'neutral' ? skillDef.element : null;

        // Bolt skills: multi-hit (1 hit per level)
        const isBolt = /bolt/i.test(skillName) || skillName === 'MG_SOULSTRIKE' || skillName === 'HW_NAPALMVULCAN';
        const totalHits = isBolt ? level : 1;
        const perHitMult = isBolt ? 100 : multiplier;

        for (let hit = 0; hit < totalHits; hit++) {
            const result = calculateMagicalDamage(
                { ...effectiveStats, ...attackerInfo, stats: effectiveStats },
                { ...targetInfo, stats: target.stats || target, hardMdef: target.hardMdef || 0 },
                { skillMultiplier: perHitMult, skillElement: skillElement || 'neutral', skillName }
            );

            if (!result.isMiss && result.damage > 0 && target.health !== undefined) {
                target.health = Math.max(0, target.health - result.damage);
            }

            // Stagger broadcast for multi-hit
            const delay = hit * 200;
            setTimeout(() => {
                broadcastToZone(zone, 'skill:effect_damage', {
                    attackerId: casterId, targetId: target.enemyId || targetId,
                    skillId: skillDef.id, skillName: skillDef.displayName || skillName,
                    damage: result.damage, hitType: result.hitType, element: result.element,
                    isEnemy: targetIsEnemy,
                    targetHealth: target.health || 0, targetMaxHealth: target.maxHealth || 0,
                    hitNumber: hit + 1, totalHits,
                    isAutocast: true
                });
            }, delay);
        }

        logger.info(`[AUTOCAST] ${caster.characterName || 'Player'} proc'd ${skillName} Lv${level} (${totalHits} hits) on ${target.name || targetId}`);
    } else if (!isMagical && targetIsEnemy) {
        // Physical damage auto-cast (Bash, Bowling Bash, etc.)
        const effectiveStats = caster.stats ? getEffectiveStats(caster) : caster;
        const attackerInfo = caster.characterId ? getAttackerInfo(caster) : { weaponType: 'bare_hand', weaponElement: 'neutral', weaponLevel: 1, buffMods: {}, cardMods: null, race: 'demihuman' };
        const targetInfo = target.enemyId ? getEnemyTargetInfo(target) : { element: { type: 'neutral', level: 1 }, size: 'medium', race: 'formless', numAttackers: 1, buffMods: {} };

        const result = calculatePhysicalDamage(
            { ...effectiveStats, ...attackerInfo, stats: effectiveStats },
            { ...targetInfo, stats: target.stats || target, hardDef: target.hardDef || 0 },
            { isSkill: true, skillMultiplier: multiplier, forceHit: true, skillElement: skillDef.element === 'neutral' ? null : skillDef.element, skillName }
        );

        if (!result.isMiss && result.damage > 0 && target.health !== undefined) {
            target.health = Math.max(0, target.health - result.damage);
        }

        broadcastToZone(zone, 'skill:effect_damage', {
            attackerId: casterId, targetId: target.enemyId || targetId,
            skillId: skillDef.id, skillName: skillDef.displayName || skillName,
            damage: result.damage, hitType: result.hitType, element: result.element,
            isEnemy: targetIsEnemy,
            targetHealth: target.health || 0, targetMaxHealth: target.maxHealth || 0,
            hitNumber: 1, totalHits: 1, isAutocast: true
        });

        logger.info(`[AUTOCAST] ${caster.characterName || 'Player'} proc'd ${skillName} Lv${level} for ${result.damage} on ${target.name || targetId}`);
    }
}

/**
 * Phase 8: Process card drop bonuses on monster kill
 * Returns array of extra items to add to inventory
 */
function processCardDropBonuses(attacker, enemy) {
    const extraDrops = [];
    const monsterRace = enemy.race || 'formless';

    // bAddMonsterDropItem: extra item drops
    if (attacker.cardAddMonsterDropItem && attacker.cardAddMonsterDropItem.length > 0) {
        for (const drop of attacker.cardAddMonsterDropItem) {
            if (drop.race !== 'all' && drop.race !== monsterRace) continue;
            if (Math.random() * 10000 < drop.chance) {
                const itemDef = itemDefinitions.get(drop.itemId);
                if (itemDef) {
                    extraDrops.push({
                        itemId: drop.itemId, itemName: itemDef.name, quantity: 1,
                        icon: itemDef.icon || 'default_item', itemType: itemDef.item_type || 'etc'
                    });
                }
            }
        }
    }

    // System N: bAddMonsterDropItemGroup — pick random item from group
    if (attacker.cardAddMonsterDropItemGroup && attacker.cardAddMonsterDropItemGroup.length > 0) {
        for (const drop of attacker.cardAddMonsterDropItemGroup) {
            if (Math.random() * 10000 < drop.chance) {
                const itemId = pickRandomFromGroup(drop.group);
                if (itemId) {
                    const itemDef = itemDefinitions.get(itemId);
                    if (itemDef) {
                        extraDrops.push({
                            itemId, itemName: itemDef.name, quantity: 1,
                            icon: itemDef.icon || 'default_item', itemType: itemDef.item_type || 'etc'
                        });
                    }
                }
            }
        }
    }

    return extraDrops;
}

// Pet stat bonuses — applied when pet intimacy >= 750 (Cordial)
function getPetBonuses(characterId) {
    const petState = activePets.get(characterId);
    if (!petState || petState.intimacy < PET_INTIMATE.CORDIAL) return {};
    const petData = getPetData(petState.mobId);
    if (!petData || !petData.bonuses) return {};
    return { ...petData.bonuses };
}

function recalcPetBonuses(player, characterId) {
    player.petBonuses = getPetBonuses(characterId);
    // Re-emit stats to client so bonuses take effect
    const socket = io.sockets.sockets.get(player.socketId);
    if (socket) {
        const effectiveStats = getEffectiveStats(player);
        const derived = calculateDerivedStats(player.stats, player);
        const finalAspd = calculateASPD(player);
        socket.emit('player:stats', buildFullStatsPayload(characterId, player, effectiveStats, derived, finalAspd));
    }
}

// Merge base stats with equipment bonuses + card bonuses + passive skill bonuses + buff modifiers
function getEffectiveStats(player) {
    const bonuses = player.equipmentBonuses || {};
    const cardB = player.cardBonuses || {};
    const passive = getPassiveSkillBonuses(player);
    const buffMods = getBuffStatModifiers(player);
    const pet = player.petBonuses || {};
    return {
        str: (player.stats.str || 1) + (bonuses.str || 0) + (cardB.str || 0) + (buffMods.strBonus || 0) + (passive.bonusSTR || 0) + (pet.str || 0),
        agi: (player.stats.agi || 1) + (bonuses.agi || 0) + (cardB.agi || 0) + (buffMods.agiBonus || 0) + (pet.agi || 0),
        vit: (player.stats.vit || 1) + (bonuses.vit || 0) + (cardB.vit || 0) + (buffMods.vitBonus || 0) + (pet.vit || 0),
        int: (player.stats.int || 1) + (bonuses.int || 0) + (cardB.int || 0) + (buffMods.intBonus || 0) + (passive.bonusINT || 0) + (pet.int || 0),
        dex: (player.stats.dex || 1) + (bonuses.dex || 0) + (cardB.dex || 0) + (buffMods.dexBonus || 0) + (passive.bonusDEX || 0) + (pet.dex || 0),
        luk: (player.stats.luk || 1) + (bonuses.luk || 0) + (cardB.luk || 0) + (buffMods.lukBonus || 0) + (pet.luk || 0),
        level: player.stats.level || 1,
        weaponATK: (player.stats.weaponATK || 0) + (cardB.atk || 0),
        passiveATK: passive.bonusATK + ((player.spiritSpheres || 0) * 3) + (buffMods.bonusATK || 0),
        statPoints: player.stats.statPoints || 0,
        bonusHit: (bonuses.hit || 0) + (cardB.hit || 0) + (passive.bonusHIT || 0) + (buffMods.bonusHit || 0) + (pet.hit || 0),
        bonusFlee: (bonuses.flee || 0) + (cardB.flee || 0) + (passive.bonusFLEE || 0) + (buffMods.bonusFlee || 0) + (pet.flee || 0),
        bonusCritical: (bonuses.critical || 0) + (cardB.critical || 0) + (buffMods.bonusCritical || 0) + (pet.critical || 0),
        bonusPerfectDodge: (bonuses.perfectDodge || 0) + (cardB.perfectDodge || 0) + (buffMods.bonusPerfectDodge || 0) + (pet.perfectDodge || 0),
        bonusMaxHp: (bonuses.maxHp || 0) + (cardB.maxHp || 0) + (buffMods.bonusMaxHp || 0) + (pet.maxHP || 0) + (passive.bonusMaxHp || 0),
        bonusMaxSp: (bonuses.maxSp || 0) + (cardB.maxSp || 0) + (buffMods.bonusMaxSp || 0) + (pet.maxSP || 0),
        bonusMaxHpRate: (player.cardMaxHpRate || 0) + (player.equipMaxHpRate || 0) + (buffMods.bonusMaxHpPercent || 0) + (pet.maxHPPercent || 0),
        bonusMaxSpRate: (player.cardMaxSpRate || 0) + (player.equipMaxSpRate || 0) + (buffMods.bonusMaxSpPercent || 0) + (pet.maxSPPercent || 0),
        equipAspdRate: (player.equipAspdRate || 0) + (player.cardAspdRate || 0),
        bonusHardDef: (cardB.def || 0) + (buffMods.bonusDEF || 0) + (pet.def || 0),
        bonusMATK: cardB.matk || 0,
        bonusHardMDEF: (cardB.mdef || 0) + (pet.mdef || 0),
        buffAtkMultiplier: buffMods.atkMultiplier,
        buffDefMultiplier: buffMods.defMultiplier,
        buffBonusMDEF: buffMods.bonusMDEF,
        passiveRaceATK: passive.raceATK,
        passiveRaceDEF: passive.raceDEF,
        passiveRaceResist: passive.raceResist,
        passiveRaceMATK: passive.raceMATK,
        doubleAttackChance: passive.doubleAttackChance || 0,
        bonusRange: passive.bonusRange || 0,
        fatalBlowChance: passive.fatalBlowChance || 0,
        // Equipment properties for derived stat formulas
        jobClass: player.jobClass || 'novice',
        weaponType: player.weaponType || 'bare_hand',
        weaponMATK: player.weaponMATK || 0,
        hardMdef: player.hardMdef || 0,
        buffAspdMultiplier: buffMods.aspdMultiplier || 1,
        // Dual wield: pass left-hand weapon type for ASPD calculation
        weaponTypeLeft: (player.equippedWeaponLeft && player.equippedWeaponLeft.weaponType) || null,
        // Mount system: pass mount state + Cavalry Mastery for ASPD penalty
        isMounted: player.isMounted || false,
        cavalierMasteryLv: passive.cavalierMasteryLv || 0,
    };
}

// Build attacker info object for the RO damage system
function getAttackerInfo(player, cachedPassive) {
    const passive = cachedPassive || getPassiveSkillBonuses(player);
    return {
        weaponType: player.weaponType || 'bare_hand',
        weaponElement: getCombinedModifiers(player).weaponElement || player.weaponElement || 'neutral',
        weaponLevel: player.weaponLevel || 1,
        weaponMATK: player.weaponMATK || 0,
        buffMods: getBuffStatModifiers(player),
        cardMods: player.cardMods || null,
        passiveRaceATK: passive.raceATK || null,
        critAtkRate: (player.equipCritAtkRate || 0) + (player.cardCritAtkRate || 0),
        race: 'demihuman',
        // Phase 1: Extended card modifiers for damage pipeline
        cardCritRace: player.cardCritRace || {},
        cardAddClass: player.cardAddClass || {},
        cardMagicRace: player.cardMagicRace || {},
        cardAddRace2: player.cardAddRace2 || {},
        cardLongAtkRate: player.cardLongAtkRate || 0,
        cardSkillAtk: player.cardSkillAtk || {},
        cardIgnoreMdefClass: player.cardIgnoreMdefClass || {},
        cardIgnoreDefClass: player.cardIgnoreDefClass,
        cardNoSizeFix: player.cardNoSizeFix || false,
        cardMatkRate: player.cardMatkRate || 0,
        cardDefRatioAtkClass: player.cardDefRatioAtkClass,
        cardAddDamageClass: player.cardAddDamageClass || {},
        cardCriticalLong: player.cardCriticalLong || 0,
        // Ammunition ATK (arrow/bullet ATK added to weapon damage)
        arrowATK: (player.equippedAmmo && player.equippedAmmo.atk) || 0,
        // Refine ATK bonus (pre-renewal: +2/+3/+5/+7 per refine level for weapon level 1/2/3/4)
        refineATK: (() => {
            const REFINE_ATK_PER_LEVEL = [0, 2, 3, 5, 7]; // index 0 unused, wlv 1-4
            const rl = player.equippedWeaponRight?.refineLevel || 0;
            const wl = player.weaponLevel || 1;
            return rl * (REFINE_ATK_PER_LEVEL[wl] || 2);
        })(),
        // Overupgrade random bonus (above safe refine limit, from rAthena refine.yml)
        overrefineMax: (() => {
            const rl = player.equippedWeaponRight?.refineLevel || 0;
            const wl = player.weaponLevel || 1;
            const safeLimit = [0, 7, 6, 5, 4][wl] || 7;
            if (rl <= safeLimit) return 0;
            const OVER_BONUS = {
                1: [0, 0, 0, 0, 0, 0, 0, 0, 3, 6, 9],
                2: [0, 0, 0, 0, 0, 0, 0, 5, 10, 15, 20],
                3: [0, 0, 0, 0, 0, 0, 8, 16, 24, 32, 40],
                4: [0, 0, 0, 0, 0, 13, 26, 39, 52, 65, 78],
            };
            return (OVER_BONUS[wl] && OVER_BONUS[wl][rl]) || 0;
        })(),
        // Dual-wield left-hand refine ATK
        refineATKLeft: (() => {
            if (!player.equippedWeaponLeft) return 0;
            const REFINE_ATK = [0, 2, 3, 5, 7];
            return (player.equippedWeaponLeft.refineLevel || 0) * (REFINE_ATK[player.equippedWeaponLeft.weaponLevel || 1] || 2);
        })(),
        // Mount state: mounted spear vs Medium = 100% (overrides 75% penalty)
        isMounted: player.isMounted || false,
    };
}

// Build target info object for enemies
function getEnemyTargetInfo(enemy) {
    // Count how many players are currently auto-attacking this enemy
    let numAttackers = 0;
    for (const [, atkState] of autoAttackState.entries()) {
        if (atkState.isEnemy && atkState.targetCharId === enemy.enemyId) {
            numAttackers++;
        }
    }
    return {
        element: enemy.element || { type: 'neutral', level: 1 },
        size: enemy.size || 'medium',
        race: enemy.race || 'formless',
        numAttackers: Math.max(1, numAttackers),
        buffMods: getBuffStatModifiers(enemy),
        passiveRaceDEF: null, // enemies don't have passive skills
        _ensembleVitDefZero: enemy._ensembleVitDefZero || false,
    };
}

// Build target info object for players
function getPlayerTargetInfo(player, targetCharId, cachedPassive) {
    // Count how many entities are auto-attacking this player
    let numAttackers = 0;
    for (const [, atkState] of autoAttackState.entries()) {
        if (!atkState.isEnemy && atkState.targetCharId === targetCharId) {
            numAttackers++;
        }
    }
    const passive = cachedPassive || getPassiveSkillBonuses(player);
    return {
        element: player.armorElement || { type: 'neutral', level: 1 },
        size: 'medium', // Players are always medium
        race: 'demihuman',
        hardMdef: player.hardMdef || 0,
        numAttackers: Math.max(1, numAttackers),
        buffMods: getBuffStatModifiers(player),
        passiveRaceDEF: passive.raceDEF || null,
        cardDefMods: player.cardDefMods || null,
        cardSubClass: player.cardSubClass || {},
        cardLongAtkDef: player.cardLongAtkDef || 0,
        cardNoMagicDamage: player.cardNoMagicDamage || 0,
        cardAddDefMonster: player.cardAddDefMonster || {},
        elementResist: (() => {
            // Merge passive elementResist (Skin Tempering, etc.) with buff elementResist (Invulnerable Siegfried)
            const passiveER = passive.elementResist || {};
            const buffER = (getBuffStatModifiers(player).elementResist) || {};
            if (!Object.keys(passiveER).length && !Object.keys(buffER).length) return null;
            const merged = { ...passiveER };
            for (const [el, pct] of Object.entries(buffER)) {
                merged[el] = (merged[el] || 0) + pct;
            }
            return merged;
        })(),
    };
}

// ============================================================
// EXP & Leveling System — Ragnarok Online Classic
// Dual progression: Base Level (stats) + Job Level (skills)
// ============================================================

// Process EXP gain for a player after killing a monster
// Returns { baseExpGained, jobExpGained, baseLevelUps[], jobLevelUps[], totalStatPoints, totalSkillPoints }
function processExpGain(player, baseExpReward, jobExpReward) {
    const result = {
        baseExpGained: 0,
        jobExpGained: 0,
        baseLevelUps: [],    // Array of { newLevel, statPointsGained }
        jobLevelUps: [],     // Array of { newJobLevel, skillPointsGained }
        totalStatPoints: 0,
        totalSkillPoints: 0
    };
    
    const baseLevel = player.stats.level || 1;
    const jobLevel = player.jobLevel || 1;
    const jobClass = player.jobClass || 'novice';
    
    // ── Base EXP Processing ──
    if (baseLevel < MAX_BASE_LEVEL) {
        player.baseExp = (player.baseExp || 0) + baseExpReward;
        result.baseExpGained = baseExpReward;
        
        // Check for multiple level ups (in case of large EXP gains)
        let currentLevel = baseLevel;
        let expNeeded = getBaseExpForNextLevel(currentLevel);
        
        while (expNeeded > 0 && player.baseExp >= expNeeded && currentLevel < MAX_BASE_LEVEL) {
            // Level up!
            player.baseExp -= expNeeded;
            currentLevel++;
            player.stats.level = currentLevel;
            
            // Grant stat points (RO formula: floor(newLevel / 5) + 3)
            const statPtsGained = getStatPointsForLevelUp(currentLevel);
            player.stats.statPoints = (player.stats.statPoints || 0) + statPtsGained;
            result.totalStatPoints += statPtsGained;
            
            result.baseLevelUps.push({
                newLevel: currentLevel,
                statPointsGained: statPtsGained
            });
            
            logger.info(`[EXP] ${player.characterName} BASE LEVEL UP! ${currentLevel - 1} → ${currentLevel} (+${statPtsGained} stat points)`);
            
            // Recalculate derived stats (maxHP/maxSP scale with level)
            const effectiveStats = getEffectiveStats(player);
            const derived = calculateDerivedStats(effectiveStats);
            player.maxHealth = derived.maxHP;
            player.maxMana = derived.maxSP;
            // Fully heal on level up (classic RO behavior)
            player.health = player.maxHealth;
            player.mana = player.maxMana;
            
            expNeeded = getBaseExpForNextLevel(currentLevel);
        }
        
        // Cap base_exp at max needed if at max level
        if (currentLevel >= MAX_BASE_LEVEL) {
            player.baseExp = 0;
        }
    }
    
    // ── Job EXP Processing ──
    const maxJobLevel = getMaxJobLevel(jobClass);
    if (jobLevel < maxJobLevel) {
        player.jobExp = (player.jobExp || 0) + jobExpReward;
        result.jobExpGained = jobExpReward;
        
        let currentJobLevel = jobLevel;
        let jobExpNeeded = getJobExpForNextLevel(jobClass, currentJobLevel);
        
        while (jobExpNeeded > 0 && player.jobExp >= jobExpNeeded && currentJobLevel < maxJobLevel) {
            // Job level up!
            player.jobExp -= jobExpNeeded;
            currentJobLevel++;
            player.jobLevel = currentJobLevel;
            
            // Grant skill points (always 1 per job level in classic RO)
            const skillPtsGained = getSkillPointsForJobLevelUp();
            player.skillPoints = (player.skillPoints || 0) + skillPtsGained;
            result.totalSkillPoints += skillPtsGained;
            
            result.jobLevelUps.push({
                newJobLevel: currentJobLevel,
                skillPointsGained: skillPtsGained
            });
            
            logger.info(`[EXP] ${player.characterName} JOB LEVEL UP! ${currentJobLevel - 1} → ${currentJobLevel} [${jobClass}] (+${skillPtsGained} skill points)`);
            
            jobExpNeeded = getJobExpForNextLevel(jobClass, currentJobLevel);
        }
        
        // Cap job_exp at 0 if at max job level
        if (currentJobLevel >= maxJobLevel) {
            player.jobExp = 0;
        }
    }
    
    return result;
}

// Save EXP and leveling data to database
async function saveExpDataToDB(characterId, player) {
    try {
        await pool.query(
            `UPDATE characters SET 
                level = $1, job_level = $2, base_exp = $3, job_exp = $4, 
                job_class = $5, stat_points = $6, skill_points = $7,
                max_health = $8, max_mana = $9, health = $10, mana = $11
             WHERE character_id = $12`,
            [
                player.stats.level || 1,
                player.jobLevel || 1,
                player.baseExp || 0,
                player.jobExp || 0,
                player.jobClass || 'novice',
                player.stats.statPoints || 0,
                player.skillPoints || 0,
                player.maxHealth,
                player.maxMana,
                player.health,
                player.mana,
                characterId
            ]
        );
        logger.debug(`[DB] Saved EXP data for character ${characterId}: BLv${player.stats.level} JLv${player.jobLevel} [${player.jobClass}]`);
    } catch (err) {
        logger.error(`[DB] Failed to save EXP data for character ${characterId}: ${err.message}`);
    }
}

// Build EXP payload for client (sent with player:stats and exp:gain events)
function buildExpPayload(player) {
    const jobClass = player.jobClass || 'novice';
    const baseLevel = player.stats.level || 1;
    const jobLevel = player.jobLevel || 1;
    return {
        baseLevel,
        jobLevel,
        baseExp: player.baseExp || 0,
        jobExp: player.jobExp || 0,
        baseExpNext: getBaseExpForNextLevel(baseLevel),
        jobExpNext: getJobExpForNextLevel(jobClass, jobLevel),
        jobClass,
        jobClassDisplayName: (JOB_CLASS_CONFIG[jobClass] || {}).displayName || jobClass,
        maxBaseLevel: MAX_BASE_LEVEL,
        maxJobLevel: getMaxJobLevel(jobClass),
        statPoints: player.stats.statPoints || 0,
        skillPoints: player.skillPoints || 0
    };
}

// RO Classic stat point cost formula: floor((currentStat - 1) / 10) + 2
function getStatPointCost(currentStatValue) {
    return Math.floor((currentStatValue - 1) / 10) + 2;
}

// Build full player:stats payload including stat allocation info
function buildFullStatsPayload(characterId, player, effectiveStats, derived, finalAspd) {
    // Calculate per-stat costs for the UI (based on BASE stats, not effective)
    const statCosts = {
        str: getStatPointCost(player.stats.str || 1),
        agi: getStatPointCost(player.stats.agi || 1),
        vit: getStatPointCost(player.stats.vit || 1),
        int: getStatPointCost(player.stats.int || 1),
        dex: getStatPointCost(player.stats.dex || 1),
        luk: getStatPointCost(player.stats.luk || 1)
    };
    // Dual wield info for client display
    const dualWieldInfo = {};
    if (isDualWielding(player)) {
        const passive = getPassiveSkillBonuses(player);
        dualWieldInfo.isDualWielding = true;
        dualWieldInfo.weaponATK_right = (player.equippedWeaponRight && player.equippedWeaponRight.atk) || 0;
        dualWieldInfo.weaponATK_left = (player.equippedWeaponLeft && player.equippedWeaponLeft.atk) || 0;
        dualWieldInfo.rightHandMasteryLv = passive.rightHandMasteryLv;
        dualWieldInfo.leftHandMasteryLv = passive.leftHandMasteryLv;
        dualWieldInfo.rightHandDamagePercent = 50 + (passive.rightHandMasteryLv * 10);
        dualWieldInfo.leftHandDamagePercent = 30 + (passive.leftHandMasteryLv * 10);
        dualWieldInfo.weaponTypeRight = (player.equippedWeaponRight && player.equippedWeaponRight.weaponType) || null;
        dualWieldInfo.weaponTypeLeft = (player.equippedWeaponLeft && player.equippedWeaponLeft.weaponType) || null;
        dualWieldInfo.elementRight = (player.equippedWeaponRight && player.equippedWeaponRight.element) || 'neutral';
        dualWieldInfo.elementLeft = (player.equippedWeaponLeft && player.equippedWeaponLeft.element) || 'neutral';
    } else {
        dualWieldInfo.isDualWielding = false;
    }

    // Aggregate elemental resistances from all sources for advanced stats display
    const passiveBonuses = getPassiveSkillBonuses(player);
    const buffModsForResist = getBuffStatModifiers(player);
    const elementResist = { neutral: 0, fire: 0, water: 0, earth: 0, wind: 0, poison: 0, holy: 0, dark: 0, ghost: 0, undead: 0 };
    // Passive element resists (Skin Tempering fire/neutral, etc.)
    if (passiveBonuses.elementResist) {
        for (const [el, pct] of Object.entries(passiveBonuses.elementResist)) {
            if (elementResist.hasOwnProperty(el)) elementResist[el] += pct;
        }
    }
    // Faith holy resist (passive, separate field)
    if (passiveBonuses.holyResist) elementResist.holy += passiveBonuses.holyResist;
    // Buff element resists (Invulnerable Siegfried, etc.)
    if (buffModsForResist.elementResist && typeof buffModsForResist.elementResist === 'object') {
        for (const [el, pct] of Object.entries(buffModsForResist.elementResist)) {
            if (elementResist.hasOwnProperty(el)) elementResist[el] += pct;
        }
    }
    // Providence holy resist (buff, separate field)
    if (buffModsForResist.holyResist) elementResist.holy += buffModsForResist.holyResist;
    // Card-based element resists
    if (player.cardElementResist) {
        for (const [el, pct] of Object.entries(player.cardElementResist)) {
            if (elementResist.hasOwnProperty(el)) elementResist[el] += pct;
        }
    }

    return {
        characterId,
        stats: {
            ...player.stats,
            str: effectiveStats.str, agi: effectiveStats.agi, vit: effectiveStats.vit,
            int: effectiveStats.int, dex: effectiveStats.dex, luk: effectiveStats.luk,
            hardDef: (player.hardDef || 0) + (effectiveStats.bonusHardDef || 0),
            hardMdef: (player.hardMdef || 0) + (effectiveStats.bonusHardMDEF || 0),
            weaponMATK: player.weaponMATK || 0,
            passiveATK: effectiveStats.passiveATK || 0,
            refineATK: getAttackerInfo(player).refineATK || 0,
            arrowATK: (player.equippedAmmo && player.equippedAmmo.atk) || 0
        },
        baseStats: {
            str: player.stats.str || 1, agi: player.stats.agi || 1, vit: player.stats.vit || 1,
            int: player.stats.int || 1, dex: player.stats.dex || 1, luk: player.stats.luk || 1
        },
        statCosts,
        derived: (() => {
            // Get buff modifiers directly for stats not in effectiveStats (moveSpeed, defPercent)
            const statBuffMods = getCombinedModifiers(player);
            const angelusDEF = (statBuffMods.defPercent || 0) > 0 ? (1 + statBuffMods.defPercent / 100) : 1;
            const buffMoveSpeedBonus = statBuffMods.moveSpeedBonus || 0;
            return {
                ...derived,
                statusATK: Math.floor(derived.statusATK * (effectiveStats.buffAtkMultiplier || 1)),
                softDEF: Math.floor(derived.softDEF * (effectiveStats.buffDefMultiplier || 1) * angelusDEF),
                softMDEF: derived.softMDEF + (effectiveStats.buffBonusMDEF || 0),
                aspd: finalAspd,
                // Movement speed (base 150ms/cell, lower = faster)
                moveSpeed: Math.max(20, Math.floor(
                    150 * (100 - (player.cardSpeedRate || 0)) / 100
                    / (1 + buffMoveSpeedBonus / 100)
                    / (player.isMounted ? 1.36 : 1)
                    * (player.hasCart ? (100 / (50 + 5 * ((player.learnedSkills || {})[604] || 0))) : 1)
                )),
            };
        })(),
        exp: buildExpPayload(player),
        dualWield: dualWieldInfo,
        isMounted: player.isMounted || false,
        spiritSpheres: player.spiritSpheres || 0,
        maxSpiritSpheres: player.maxSpiritSpheres || 0,
        elementResist,
        blockChance: (() => {
            const agBuff = (player.activeBuffs || []).find(b => b.name === 'auto_guard' && Date.now() < b.expiresAt);
            return agBuff ? (agBuff.blockChance || 0) : 0;
        })(),
        // Race/Size/Element offense & defense for advanced stats display
        advancedCombat: (() => {
            const cm = player.cardMods || {};
            const cd = player.cardDefMods || {};
            const races = ['formless', 'undead', 'brute', 'plant', 'insect', 'fish', 'demon', 'demihuman', 'angel', 'dragon'];
            const sizes = ['small', 'medium', 'large'];
            const raceAtk = {};
            const raceDef = {};
            const sizeAtk = {};
            const sizeDef = {};
            const eleAtk = {};
            // Card-based race/size/element ATK bonuses
            for (const r of races) { raceAtk[r] = (cm[`race_${r}`] || 0); raceDef[r] = (cd[`race_${r}`] || 0); }
            for (const s of sizes) { sizeAtk[s] = (cm[`size_${s}`] || 0); sizeDef[s] = (cd[`size_${s}`] || 0); }
            for (const el of ['neutral','fire','water','earth','wind','poison','holy','dark','ghost','undead']) {
                eleAtk[el] = cm[`ele_${el}`] || 0;
                // Card ele defense already in elementResist via cardElementResist — skip to avoid double
            }
            // Passive race ATK (Demon Bane, Beast Bane, Dragonology)
            if (passiveBonuses.raceATK) {
                for (const [r, v] of Object.entries(passiveBonuses.raceATK)) raceAtk[r] = (raceAtk[r] || 0) + v;
            }
            // Passive race DEF (Divine Protection)
            if (passiveBonuses.raceDEF) {
                for (const [r, v] of Object.entries(passiveBonuses.raceDEF)) raceDef[r] = (raceDef[r] || 0) + v;
            }
            // Passive race resist % (Dragonology)
            if (passiveBonuses.raceResist) {
                for (const [r, v] of Object.entries(passiveBonuses.raceResist)) raceDef[r] = (raceDef[r] || 0) + v;
            }
            // Buff demon/holy resist (Providence)
            if (buffModsForResist.demonResist) raceDef.demon = (raceDef.demon || 0) + buffModsForResist.demonResist;
            return { raceAtk, raceDef, sizeAtk, sizeDef, eleAtk };
        })(),
    };
}

// Helper: emit spirit sphere update to player + zone
function emitSphereUpdate(player, characterId, zone) {
    const sock = io.sockets.sockets.get(player.socketId);
    if (sock) sock.emit('sphere:update', { characterId, sphereCount: player.spiritSpheres, maxSpheres: player.maxSpiritSpheres });
    broadcastToZone(zone, 'sphere:update', { characterId, sphereCount: player.spiritSpheres, maxSpheres: player.maxSpiritSpheres });
}

// ============================================================
// Enemy/NPC System — Ragnarok Online Pre-Renewal Monsters
// 509 monsters from rAthena database + compatibility adapter
// ============================================================
const enemies = new Map();
let nextEnemyId = 2000001;

// Build ENEMY_TEMPLATES from RO_MONSTER_TEMPLATES
// This adapter converts RO template format → game-compatible format
const ENEMY_TEMPLATES = {};
for (const [key, ro] of Object.entries(RO_MONSTER_TEMPLATES)) {
    ENEMY_TEMPLATES[key] = {
        id: ro.id,
        name: ro.name,
        level: ro.level,
        maxHealth: ro.maxHealth,
        damage: ro.attack,                        // RO Attack → game damage
        attackRange: ro.attackRange,               // Already converted (cells * 50)
        aggroRange: ro.aggroRange,                 // 0 for passive mobs
        chaseRange: ro.chaseRange,
        aspd: ro.aspd,
        exp: ro.baseExp + ro.jobExp,               // Total EXP = Base + Job
        baseExp: ro.baseExp,
        jobExp: ro.jobExp,
        mvpExp: ro.mvpExp,
        respawnMs: ro.respawnMs,
        aiType: ro.aiType,
        monsterClass: ro.monsterClass,             // normal/boss/mvp
        size: ro.size,                             // small/medium/large
        race: ro.race,                             // plant/insect/brute/etc
        element: ro.element,                       // { type, level }
        walkSpeed: ro.walkSpeed,
        attackDelay: ro.attackDelay,
        attackMotion: ro.attackMotion,
        damageMotion: ro.damageMotion,
        attack2: ro.attack2,                       // Max attack (pre-renewal)
        defense: ro.defense,                       // Hard DEF
        magicDefense: ro.magicDefense,             // Hard MDEF
        raceGroups: ro.raceGroups || {},
        stats: { ...ro.stats },
        modes: { ...ro.modes },
        // Drop format: { itemName, itemId (resolved lazily at drop time), chance (decimal), rate (%) }
        drops: (ro.drops || []).map(d => ({
            itemName: d.itemName,
            itemId: null,  // Resolved lazily from itemNameToId after DB load
            chance: d.rate / 100,                  // Convert % to decimal for Math.random()
            rate: d.rate,                          // Keep original % for display
            stealProtected: d.stealProtected || false
        })),
        mvpDrops: (ro.mvpDrops || []).map(d => ({
            itemName: d.itemName,
            itemId: null,  // Resolved lazily from itemNameToId after DB load
            chance: d.rate / 100,
            rate: d.rate
        })),
        // Sprite rendering (optional — client skips if absent)
        spriteClass: ro.spriteClass || null,
        weaponMode: ro.weaponMode != null ? ro.weaponMode : 0
    };
}

const RO_TEMPLATE_COUNT = Object.keys(ENEMY_TEMPLATES).length;
logger.info(`[ENEMY] Loaded ${RO_TEMPLATE_COUNT} RO monster templates`);

// Reverse lookup: numeric RO monster ID → string template key (for NPC_SUMMONSLAVE / NPC_METAMORPHOSIS)
const RO_ID_TO_TEMPLATE_KEY = {};
for (const [key, ro] of Object.entries(RO_MONSTER_TEMPLATES)) {
    RO_ID_TO_TEMPLATE_KEY[ro.id] = key;
}
logger.info(`[ENEMY] Built RO_ID_TO_TEMPLATE_KEY with ${Object.keys(RO_ID_TO_TEMPLATE_KEY).length} entries`);

// Drop resolution happens lazily after itemDefinitions are loaded from DB
// See resolveDropItemIds() called after loadItemDefinitions()
function resolveDropItemIds() {
    let resolvedDrops = 0, unresolvedDrops = 0;
    for (const t of Object.values(ENEMY_TEMPLATES)) {
        for (const d of t.drops) {
            if (d.itemName && !d.itemId) {
                d.itemId = itemNameToId.get(d.itemName) || null;
            }
            if (d.itemId) resolvedDrops++; else unresolvedDrops++;
        }
        for (const d of (t.mvpDrops || [])) {
            if (d.itemName && !d.itemId) {
                d.itemId = itemNameToId.get(d.itemName) || null;
            }
        }
    }
    logger.info(`[ENEMY] Drop itemId resolution: ${resolvedDrops} resolved, ${unresolvedDrops} unresolved (from ${itemNameToId.size} DB items)`);
}

